import React, { useState } from 'react';
import { AppView, HousePlan, Rendering, SavedDesign, Room } from './types';
import HomePage from './components/HomePage';
import ResultsPage from './components/ResultsPage';
import Header from './components/Header';
import { callGeminiAPI } from './services/geminiService';
import LoadingOverlay from './components/LoadingOverlay';

function App() {
  const [currentView, setCurrentView] = useState<AppView>(AppView.Home);
  const [housePlan, setHousePlan] = useState<HousePlan | null>(null);
  const [apiKey, setApiKey] = useState<string>('');
  const [isLoading, setIsLoading] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);

  const handleCreateNewDesign = async (prompt: string, customizations: { [key: string]: string }) => {
    setIsLoading(true);
    setError(null);
    try {
      const response = await callGeminiAPI(prompt, apiKey, customizations);
      setHousePlan(response);
      setCurrentView(AppView.Results);
    } catch (e) {
      if (e instanceof Error) {
        setError(e.message);
      } else {
        setError('An unknown error occurred.');
      }
    } finally {
      setIsLoading(false);
    }
  };

  const handleApiKeySubmit = (key: string) => {
    setApiKey(key);
  };

  const handleGoHome = () => {
    setCurrentView(AppView.Home);
    setHousePlan(null);
  };

  return (
    <div className="App w-full h-full bg-gray-100 flex flex-col items-center">
      <Header onGoHome={handleGoHome} />
      {isLoading && <LoadingOverlay />}
      {apiKey === '' ? (
        <ApiKeyPrompt onApiKeySubmit={handleApiKeySubmit} />
      ) : (
        <>
          {currentView === AppView.Home && (
            <HomePage onCreateNewDesign={handleCreateNewDesign} />
          )}
          {currentView === AppView.Results && housePlan && (
            <ResultsPage housePlan={housePlan} />
          )}
        </>
      )}
      {error && <div className="text-red-500">{error}</div>}
    </div>
  );
}

export default App;
```

