import React, { useState, useEffect, useRef } from 'react';
import { SlideshowConfig } from './types';
import { Repeat } from './Repeat';

interface Props {
  config: SlideshowConfig;
}

const ResultsPage: React.FC<Props> = ({ config }) => {
  const { images, slideshowDurationMs, repeat, audioUrl } = config;
  const [currentImageIndex, setCurrentImageIndex] = useState(0);
  const [fadeOutTimeout, setFadeOutTimeout] = useState<NodeJS.Timeout | null>(null);
  const audioRef = useRef<HTMLAudioElement>(null);
  const totalSlideshowDurationMs = images.length * slideshowDurationMs;

  useEffect(() => {
    let timeoutId: NodeJS.Timeout | null = null;

    const nextImage = () => {
      setCurrentImageIndex((prevIndex) => (prevIndex + 1) % images.length);
    };

    const scheduleNextImage = () => {
      timeoutId = setTimeout(nextImage, slideshowDurationMs);
    };

    scheduleNextImage();

    if (repeat) {
      if (fadeOutTimeout) {
        clearTimeout(fadeOutTimeout);
        setFadeOutTimeout(null);
      }
    }

    if (!repeat && audioRef.current && audioRef.current.duration > 0) {
      const fadeOutStartTime = Math.max(0, totalSlideshowDurationMs - 5000);

      fadeOutTimeout = setTimeout(() => {
          if (audioRef.current && !audioRef.current.paused) {
              console.log("Auto-fading music 5s before end...");
              fadeOutAudio(audioRef.current);
          }
      }, fadeOutStartTime);
    }

    return () => {
      if (timeoutId) {
        clearTimeout(timeoutId);
      }
      if (fadeOutTimeout) {
        clearTimeout(fadeOutTimeout);
      }
    };
  }, [currentImageIndex, slideshowDurationMs, images.length, repeat, totalSlideshowDurationMs]);

  const fadeOutAudio = (audio: HTMLAudioElement) => {
    if (audio.volume > 0.05) {
      audio.volume -= 0.05;
      setTimeout(() => fadeOutAudio(audio), 50);
    } else {
      audio.volume = 0;
      audio.pause();
    }
  };

  return (
    <div>
      <img src={images[currentImageIndex]} alt="Slideshow Image" />
      {audioUrl && (
        <audio ref={audioRef} src={audioUrl} autoPlay loop={repeat} >
          Your browser does not support the audio element.
        </audio>
      )}
    </div>
  );
};

export default ResultsPage;
--- END OF FILE src/components/ResultsPage.tsx ---
