import { doc, setDoc, getDoc, collection, getDocs, deleteDoc, addDoc, query, where } from "firebase/firestore";
import { db } from "./firebase";
import { SavedDesign, AccessLevel } from "../types";

/**
 * Compresses a Data URI or Base64 string to a JPEG under specific dimensions and quality.
 */
const compressImage = (source: string, mimeType: string = 'image/jpeg', maxWidth: number = 800, quality: number = 0.5): Promise<string> => {
  return new Promise((resolve) => {
    const img = new Image();
    // Handle both Data URI and raw Base64 inputs
    img.src = source.startsWith('data:') ? source : `data:${mimeType};base64,${source}`;

    img.onload = () => {
      const canvas = document.createElement('canvas');
      let { width, height } = img;

      // Calculate new dimensions maintaining aspect ratio
      if (width > maxWidth || height > maxWidth) {
        const ratio = Math.min(maxWidth / width, maxWidth / height);
        width = Math.floor(width * ratio);
        height = Math.floor(height * ratio);
      }

      canvas.width = width;
      canvas.height = height;
      const ctx = canvas.getContext('2d');

      if (!ctx) {
        resolve(img.src); // Fallback to original if context fails
        return;
      }

      // Fill white background (handles transparency conversion to JPEG)
      ctx.fillStyle = '#FFFFFF';
      ctx.fillRect(0, 0, width, height);
      ctx.drawImage(img, 0, 0, width, height);

      // Export as JPEG to save space
      resolve(canvas.toDataURL('image/jpeg', quality));
    };

    img.onerror = () => {
      // Fallback to original on error
      resolve(img.src);
    };
  });
};

export const cloudService = {
  /**
   * Saves a design to the user's Firestore collection.
   * Compresses images before saving to ensure the document stays under the 1MB Firestore limit.
   */
  async saveDesign(userId: string, design: SavedDesign): Promise<void> {
    if (!userId || !design) return;

    try {
      // Deep clone the design to avoid modifying the local high-res state
      const designToSave = JSON.parse(JSON.stringify(design)) as SavedDesign;

      // Threshold: ~150KB (Length of base64 string is roughly 1.33 * size in bytes)
      // We start compressing if string length is > 200,000 characters
      const SIZE_THRESHOLD = 200000; 

      // 1. Compress Renderings
      if (designToSave.renderings && designToSave.renderings.length > 0) {
        designToSave.renderings = await Promise.all(designToSave.renderings.map(async (r) => {
          if (r.imageUrl && r.imageUrl.length > SIZE_THRESHOLD) { 
             const compressedDataUri = await compressImage(r.imageUrl, 'image/jpeg', 800, 0.5);
             return { ...r, imageUrl: compressedDataUri };
          }
          return r;
        }));
      }

      // 2. Compress Uploaded Plans/Images
      if (designToSave.uploadedImages) {
        const keys = ['frontPlan', 'backPlan', 'facadeImage'] as const;
        for (const key of keys) {
            const imgData = designToSave.uploadedImages[key];
            if (imgData && imgData.base64 && imgData.base64.length > SIZE_THRESHOLD) {
                const compressedDataUri = await compressImage(imgData.base64, imgData.mimeType, 800, 0.5);
                // Split back into base64 and update mimetype to jpeg
                designToSave.uploadedImages[key] = {
                    base64: compressedDataUri.split(',')[1],
                    mimeType: 'image/jpeg'
                };
            }
        }
      }

      // 3. Emergency Size Check
      // Firestore limit is 1,048,576 bytes. We check estimate JSON size.
      const jsonString = JSON.stringify(designToSave);
      const estimatedSize = new TextEncoder().encode(jsonString).length;

      if (estimatedSize >= 1000000) { // If still close to 1MB
          console.warn(`Design size ${estimatedSize} exceeds safe limit. Applying emergency compression.`);

          // Emergency pass: Compress ALL renderings aggressively
          if (designToSave.renderings) {
             designToSave.renderings = await Promise.all(designToSave.renderings.map(async (r) => {
                 // Force compression on everything to 600px width and low quality
                 const compressedDataUri = await compressImage(r.imageUrl, 'image/jpeg', 600, 0.4);
                 return { ...r, imageUrl: compressedDataUri };
             }));
          }

          // Emergency pass: Compress uploaded images
           if (designToSave.uploadedImages) {
                const keys = ['frontPlan', 'backPlan', 'facadeImage'] as const;
                for (const key of keys) {
                    const imgData = designToSave.uploadedImages[key];
                    if (imgData && imgData.base64) {
                        const compressedDataUri = await compressImage(imgData.base64, imgData.mimeType, 600, 0.4);
                        designToSave.uploadedImages[key] = {
                            base64: compressedDataUri.split(',')[1],
                            mimeType: 'image/jpeg'
                        };
                    }
                }
            }
      }

      // We create a reference to: users -> {userId} -> designs -> {designId}
      const designRef = doc(db, "users", userId, "designs", design.housePlan.id);

      const dataToSave = {
        ...designToSave,
        userId: userId, // Ensure owner ID is stamped on the doc
        lastSynced: Date.now()
      };

      // Remove transient fields if present before saving
      delete (dataToSave as any).accessLevel;

      await setDoc(designRef, dataToSave);
      console.log("Design saved to cloud successfully");
    } catch (error) {
      console.error("Error saving design to cloud:", error);
      // We throw specifically to let the UI know if the limit was still hit (unlikely with compression)
      throw error;
    }
  },

  /**
   * Retrieves all designs for a specific user from Firestore.
   */
  async getUserDesigns(userId: string): Promise<SavedDesign[]> {
    if (!userId) return [];

    try {
      const designsRef = collection(db, "users", userId, "designs");
      const querySnapshot = await getDocs(designsRef);

      const designs: SavedDesign[] = [];
      querySnapshot.forEach((doc) => {
        const data = doc.data() as SavedDesign;
        // Owned designs have 'owner' access level by default
        designs.push({ ...data, ownerId: userId, accessLevel: 'owner' });
      });

      return designs;
    } catch (error) {
      console.error("Error fetching designs from cloud:", error);
      throw error;
    }
  },

  /**
   * Deletes a design from the cloud.
   */
  async deleteDesign(userId: string, designId: string): Promise<void> {
    if (!userId || !designId) return;

    try {
      const designRef = doc(db, "users", userId, "designs", designId);
      await deleteDoc(designRef);
    } catch (error) {
      console.error("Error deleting design from cloud:", error);
      throw error;
    }
  },

  /**
   * Shares a design with another user by email.
   */
  async shareDesign(ownerId: string, designId: string, targetEmail: string, permission: AccessLevel): Promise<void> {
      try {
          // Normalize email
          const email = targetEmail.trim().toLowerCase();

          // Add to 'shared_projects' collection
          await addDoc(collection(db, "shared_projects"), {
              ownerId,
              designId,
              targetEmail: email,
              permission,
              createdAt: Date.now()
          });
      } catch (error) {
          console.error("Error sharing design:", error);
          throw error;
      }
  },

  /**
   * Fetches designs shared with the given email address.
   */
  async getSharedDesigns(userEmail: string): Promise<SavedDesign[]> {
      try {
          const email = userEmail.trim().toLowerCase();
          const q = query(collection(db, "shared_projects"), where("targetEmail", "==", email));
          const querySnapshot = await getDocs(q);

          const sharedDesigns: SavedDesign[] = [];

          for (const shareDoc of querySnapshot.docs) {
              const { ownerId, designId, permission } = shareDoc.data();

              // Fetch the actual design
              try {
                const designRef = doc(db, "users", ownerId, "designs", designId);
                const designSnap = await getDoc(designRef);

                if (designSnap.exists()) {
                    const designData = designSnap.data() as SavedDesign;
                    sharedDesigns.push({
                        ...designData,
                        ownerId: ownerId,
                        accessLevel: permission as AccessLevel
                    });
                } else {
                    console.warn(`Shared design not found: ${designId} owned by ${ownerId}`);
                }
              } catch (err) {
                  console.error(`Failed to fetch shared design ${designId}`, err);
              }
          }
          return sharedDesigns;

      } catch (error) {
          console.error("Error fetching shared designs:", error);
          return [];
      }
  },

  /**
   * Removes a share record (stop sharing or remove from 'Shared with me')
   */
  async removeShare(userEmail: string, designId: string): Promise<void> {
      // This is a simplification. Ideally we'd delete by ID, but searching by composite key works for now.
      try {
        const email = userEmail.trim().toLowerCase();
        const q = query(
            collection(db, "shared_projects"), 
            where("targetEmail", "==", email),
            where("designId", "==", designId)
        );
        const snapshot = await getDocs(q);
        snapshot.forEach(async (doc) => {
            await deleteDoc(doc.ref);
        });
      } catch (error) {
          console.error("Error removing share:", error);
      }
  }
};

import React, { useState, useCallback, useEffect, useMemo, useRef } from 'react';
import { AppView, HousePlan, Rendering, SavedDesign, Room, User, AccessLevel } from './types';
import HomePage from './components/HomePage';
import ResultsPage from './components/ResultsPage';
import Header from './components/Header';
import LandingPage from './components/LandingPage';
import { generateHousePlanFromDescription, generateImage, generateVideo, generateImageFromImage } from './services/geminiService';
import { authService } from './services/authService';
import { dbService } from './services/dbService';
import { cloudService } from './services/cloudService';
import LoadingOverlay from './components/LoadingOverlay';
import ApiKeyPrompt from './components/ApiKeyPrompt';
import ShareModal from './components/ShareModal';

interface UploadedFiles {
    frontPlan: File | null;
    backPlan: File | null;
    facadeImage: File | null;
}

function App() {
  const [view, setView] = useState<AppView>(AppView.Home);
  const [isLoading, setIsLoading] = useState(false);
  const [isAuthLoading, setIsAuthLoading] = useState(true);
  const [isSavingCloud, setIsSavingCloud] = useState(false);
  const [loadingMessage, setLoadingMessage] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [videoUrl, setVideoUrl] = useState<string | null>(null);

  const [savedDesigns, setSavedDesigns] = useState<SavedDesign[]>([]);
  const [currentDesignId, setCurrentDesignId] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [isKeyReady, setIsKeyReady] = useState<boolean | null>(null);
  const [isShareModalOpen, setIsShareModalOpen] = useState(false);

  const [user, setUser] = useState<User | null>(null);
  const userRef = useRef<User | null>(null); // To track previous user for migration logic

  const getUserId = useCallback(() => {
    return user ? user.email : 'anonymous';
  }, [user]);

  // Calculate total renderings to enforce guest limits (only count owned designs)
  const totalRenderingsCount = useMemo(() => {
    return savedDesigns.filter(d => d.accessLevel === 'owner').reduce((acc, design) => acc + design.renderings.length, 0);
  }, [savedDesigns]);

  // Subscribe to authentication state changes
  useEffect(() => {
    const unsubscribe = authService.onAuthStateChanged((newUser) => {
      const prevEmail = userRef.current?.email;
      const newEmail = newUser?.email;

      if (prevEmail !== newEmail) {
          setUser(newUser);
      }
      setIsAuthLoading(false);
    });
    return () => unsubscribe();
  }, []);

  // Handle data migration and initial data load
  useEffect(() => {
      const handleDataLoadAndMigration = async () => {
        const currentUser = user;
        const previousUser = userRef.current;
        const currentUserId = currentUser ? currentUser.email : 'anonymous';

        userRef.current = currentUser;

        if (!currentUser) {
            setSavedDesigns([]);
            return;
        }

        // Migration Logic
        if (currentUser && !previousUser) {
             try {
                const anonymousDesigns = await dbService.getUserDesigns('anonymous');
                if (anonymousDesigns.length > 0) {
                    setTimeout(async () => {
                         if (window.confirm(`Welcome ${currentUser.name}! You have designs saved as a guest. Would you like to move them to your account?`)) {
                            await dbService.reassignDesigns('anonymous', currentUser.email);
                            try {
                                const designs = await dbService.getUserDesigns(currentUser.email);
                                for (const design of designs) {
                                    await cloudService.saveDesign(currentUser.email, design);
                                }
                            } catch (err) {
                                console.warn("Background cloud sync failed during migration", err);
                            }
                            const designs = await dbService.getUserDesigns(currentUser.email);
                            setSavedDesigns(designs);
                        }
                    }, 500);
                }
             } catch (e) {
                 console.error("Error checking for anonymous designs:", e);
             }
        }

        // Standard Data Loading
        try {
            // 1. Load Local Designs
            let allDesigns = await dbService.getUserDesigns(currentUserId);
            // Assign owner access level to locally loaded designs for consistency
            allDesigns = allDesigns.map(d => ({ ...d, ownerId: currentUserId, accessLevel: 'owner' }));

            // 2. Load Cloud Designs (Owned + Shared)
            if (currentUser && currentUser.email !== 'anonymous') {
                try {
                    // Fetch Owned
                    const cloudOwned = await cloudService.getUserDesigns(currentUserId);

                    // Fetch Shared
                    const cloudShared = await cloudService.getSharedDesigns(currentUser.email);

                    // Merge strategies
                    // We prioritize Cloud versions for shared designs.
                    // For owned designs, we use cloud versions to sync, and update local cache.

                    // 1. Update local DB with owned cloud designs
                    for (const d of cloudOwned) {
                        await dbService.saveDesign(d, currentUserId);
                    }

                    // Re-read local DB to get updated owned designs
                    const refreshedLocal = await dbService.getUserDesigns(currentUserId);
                    const finalOwned = refreshedLocal.map(d => ({ ...d, ownerId: currentUserId, accessLevel: 'owner' as AccessLevel }));

                    // Combine
                    allDesigns = [...finalOwned, ...cloudShared];
                } catch (cloudErr) {
                    console.error("Cloud fetch failed, using local", cloudErr);
                }
            }

            setSavedDesigns(allDesigns);

        } catch (e) {
            console.error("Failed to load designs:", e);
            setError("Could not load saved designs.");
        }
      };

      if (!isAuthLoading) {
          handleDataLoadAndMigration();
      }
  }, [user, isAuthLoading]);


  const checkApiKey = useCallback(async () => {
    if (window.aistudio && typeof window.aistudio.hasSelectedApiKey === 'function') {
      try {
        const hasKey = await window.aistudio.hasSelectedApiKey();
        setIsKeyReady(hasKey);
      } catch (e) {
        console.error("Error checking for API key:", e);
        setIsKeyReady(false);
      }
    } else {
      setIsKeyReady(true);
    }
  }, []);

  useEffect(() => {
    checkApiKey();
  }, [checkApiKey]);

  const currentDesign = useMemo(() => {
    return savedDesigns.find(d => d.housePlan.id === currentDesignId) || null;
  }, [currentDesignId, savedDesigns]);

  const filteredDesigns = useMemo(() => {
    const sorted = [...savedDesigns].sort((a, b) => b.housePlan.createdAt - a.housePlan.createdAt);
    if (!searchQuery) return sorted;

    return sorted.filter(design => {
      const query = searchQuery.toLowerCase();
      const { title, style, rooms } = design.housePlan;
      return (
        title.toLowerCase().includes(query) ||
        style.toLowerCase().includes(query) ||
        rooms.some(room => room.name.toLowerCase().includes(query)) ||
        design.initialPrompt.toLowerCase().includes(query)
      );
    });
  }, [searchQuery, savedDesigns]);

  // Update design: Handles both local (owned) and shared (cloud) updates
  const saveDesignChange = useCallback(async (updatedDesign: SavedDesign) => {
      const currentUserId = getUserId();
      // Determine effective owner
      const designOwnerId = updatedDesign.ownerId || currentUserId;
      const isOwner = designOwnerId === currentUserId;

      try {
          // Update State
          setSavedDesigns(prev => {
              const idx = prev.findIndex(d => d.housePlan.id === updatedDesign.housePlan.id);
              if (idx >= 0) {
                  const newArr = [...prev];
                  newArr[idx] = updatedDesign;
                  return newArr;
              } else {
                  return [...prev, updatedDesign];
              }
          });

          if (isOwner) {
            // Save to Local DB if owner
            await dbService.saveDesign(updatedDesign, currentUserId);
          }

          // Save to Cloud (if logged in)
          // Use designOwnerId to save to the correct path in Firestore
          if (user && user.email !== 'anonymous') {
             await cloudService.saveDesign(designOwnerId, updatedDesign);
          }

      } catch (err) {
          console.error("Failed to save design:", err);
          setError("Failed to save changes.");
      }
  }, [getUserId, user]);

  const handleManualSaveToCloud = useCallback(async () => {
      if (!currentDesign) return;
      if (!user) {
          alert("You must be logged in to save to the cloud.");
          return;
      }

      setIsSavingCloud(true);
      try {
          const ownerId = currentDesign.ownerId || user.email;
          await cloudService.saveDesign(ownerId, currentDesign);

          if (ownerId === user.email) {
             await dbService.saveDesign(currentDesign, user.email);
          }
          alert("Design successfully saved!");
      } catch (err) {
          console.error(err);
          setError("Failed to save. Please try again.");
      } finally {
          setIsSavingCloud(false);
      }
  }, [currentDesign, user]);

  const handleError = useCallback((err: unknown, defaultView: AppView = AppView.Home) => {
    const errorMessage = err instanceof Error ? err.message : 'An unknown error occurred.';
    if (errorMessage.includes('billing-enabled API key') || errorMessage.includes('select a valid key') || errorMessage.includes('Requested entity was not found')) {
        setIsKeyReady(false);
    }
    setError(errorMessage);
    if (defaultView === AppView.Home) {
        setView(AppView.Home);
    }
  }, []);

  const resetApp = useCallback(() => {
    setView(AppView.Home);
    setCurrentDesignId(null);
    setError(null);
    setIsLoading(false);
    setSearchQuery('');
    setVideoUrl(prev => {
        if(prev) URL.revokeObjectURL(prev);
        return null;
    });
  }, []);

  const handleSignOut = useCallback(async () => {
    await authService.signOut();
    resetApp();
  }, [resetApp]);

  const checkGuestLimit = useCallback(() => {
     if (user?.name === 'Guest Architect' && totalRenderingsCount >= 2) {
         if (window.confirm("Guest Account Limit Reached\n\nYou are limited to 2 active renderings as a Guest.\n\nPlease Sign In with your Google Account to create unlimited designs, access cloud storage, and advanced features.\n\nClick OK to return to the login screen.")) {
             handleSignOut();
         }
         return false;
     }
     return true;
  }, [user, totalRenderingsCount, handleSignOut]);

  const handleGenerationRequest = useCallback(async (description: string, files: UploadedFiles) => {
    if (!checkGuestLimit()) return;

    setIsLoading(true);
    setError(null);
    setLoadingMessage('Processing your design inputs...');

    try {
      const imageInputs: { file: File, description: string }[] = [];
      if (files.frontPlan) imageInputs.push({ file: files.frontPlan, description: "front architectural plan" });
      if (files.backPlan) imageInputs.push({ file: files.backPlan, description: "back architectural plan" });
      if (files.facadeImage) imageInputs.push({ file: files.facadeImage, description: "example facade for style reference" });

      const processedImages = await Promise.all(imageInputs.map(async (input) => {
          const reader = new FileReader();
          const base64 = await new Promise<string>((resolve, reject) => {
              reader.onload = () => resolve((reader.result as string).split(',')[1]);
              reader.onerror = reject;
              reader.readAsDataURL(input.file);
          });
          return { base64, mimeType: input.file.type, description: input.description };
      }));

      setLoadingMessage('Designing your dream home structure...');
      const planData = await generateHousePlanFromDescription(description, processedImages);

      const newHousePlan: HousePlan = {
          ...planData,
          id: crypto.randomUUID(),
          createdAt: Date.now(),
      };

      let frontImageUrl: string;
      let frontExteriorPrompt: string;
      const facadeForRendering = processedImages.find(p => p.description.includes('facade'));

      if (facadeForRendering) {
        setLoadingMessage('Rendering 3D model from your image...');
        frontExteriorPrompt = `Using the provided example facade image as a strong style reference, create a photorealistic, high-quality 3D architectural rendering of a complete house exterior. The overall design concept is: "${description}". Enhance the lighting, textures, and surroundings to create a professional visualization.`;
        frontImageUrl = await generateImageFromImage(frontExteriorPrompt, facadeForRendering.base64, facadeForRendering.mimeType);
      } else {
        setLoadingMessage('Rendering front exterior...');
        frontExteriorPrompt = `Photorealistic 3D rendering of the front exterior of a ${newHousePlan.style} house. This image should focus on the street-facing view, including the main entrance, facade, and any front yard landscaping. The overall architectural concept is: "${description}". Crucially, DO NOT include backyard-specific features like swimming pools, large patios, or putting greens in this front view.`;
        frontImageUrl = await generateImage(frontExteriorPrompt);
      }

      const frontRendering: Rendering = {
        id: crypto.randomUUID(),
        category: 'Front Exterior',
        imageUrl: frontImageUrl,
        prompt: frontExteriorPrompt,
        liked: false,
        favorited: false
      };

      const newDesign: SavedDesign = {
        housePlan: newHousePlan,
        renderings: [frontRendering],
        initialPrompt: description,
        uploadedImages: {
            frontPlan: processedImages.find(p => p.description.includes('front architectural plan')),
            backPlan: processedImages.find(p => p.description.includes('back architectural plan')),
            facadeImage: processedImages.find(p => p.description.includes('facade'))
        },
        ownerId: getUserId(),
        accessLevel: 'owner'
      };

      await saveDesignChange(newDesign);
      setCurrentDesignId(newHousePlan.id);
      setView(AppView.Results);

    } catch (err) {
      handleError(err, AppView.Home);
    } finally {
      setIsLoading(false);
      setLoadingMessage('');
    }
  }, [saveDesignChange, handleError, getUserId, checkGuestLimit]);

  const handleNewRendering = useCallback(async (prompt: string, category: string) => {
    if (!currentDesignId) return;
    if (!checkGuestLimit()) return;

    setIsLoading(true);
    setLoadingMessage(`Rendering ${category}...`);
    setError(null);
    try {
      const design = savedDesigns.find(d => d.housePlan.id === currentDesignId);
      if (!design) return;

      let imageUrl: string;
      const backPlanImage = design?.uploadedImages?.backPlan;

      if (category === 'Back Exterior' && backPlanImage) {
        imageUrl = await generateImageFromImage(prompt, backPlanImage.base64, backPlanImage.mimeType);
      } else {
        imageUrl = await generateImage(prompt);
      }

      const newRendering: Rendering = {
        id: crypto.randomUUID(),
        category,
        imageUrl,
        prompt,
        liked: false,
        favorited: false
      };

      const updatedDesign = { ...design, renderings: [...design.renderings, newRendering] };
      await saveDesignChange(updatedDesign);

    } catch (err) {
      handleError(err);
    } finally {
      setIsLoading(false);
      setLoadingMessage('');
    }
  }, [currentDesignId, savedDesigns, saveDesignChange, handleError, checkGuestLimit]);

  const handleRecreateRendering = useCallback(async (category: string) => {
    if (!currentDesignId) return;
    const design = savedDesigns.find(d => d.housePlan.id === currentDesignId);
    if (!design) return;

    // Check permissions (must have edit access)
    if (design.accessLevel === 'view') {
        alert("You have 'View Only' access to this project.");
        return;
    }

    const existingRendering = design.renderings.find(r => r.category === category);

    if (!existingRendering || (category !== 'Front Exterior' && category !== 'Back Exterior')) return;

    setIsLoading(true);
    setLoadingMessage(`Re-creating ${category}...`);
    setError(null);

    try {
      const { prompt } = existingRendering;
      let imageUrl: string;

      if (category === 'Front Exterior') {
         const facadeImage = design.uploadedImages?.facadeImage;
         if (facadeImage && prompt.includes("example facade")) {
            imageUrl = await generateImageFromImage(prompt, facadeImage.base64, facadeImage.mimeType);
         } else {
            imageUrl = await generateImage(prompt);
         }
      } else { // Back Exterior
         const backPlan = design.uploadedImages?.backPlan;
         if (backPlan) {
            imageUrl = await generateImageFromImage(prompt, backPlan.base64, backPlan.mimeType);
         } else {
            imageUrl = await generateImage(prompt);
         }
      }

      const updatedRendering: Rendering = {
          ...existingRendering,
          imageUrl,
      };

      const newRenderings = design.renderings.map(r => r.id === existingRendering.id ? updatedRendering : r);
      const updatedDesign = { ...design, renderings: newRenderings };
      await saveDesignChange(updatedDesign);

    } catch (err) {
      handleError(err);
    } finally {
      setIsLoading(false);
      setLoadingMessage('');
    }
  }, [currentDesignId, savedDesigns, saveDesignChange, handleError]);


  const handleGenerateVideoTour = useCallback(async (prompt: string) => {
      setIsLoading(true);
      setLoadingMessage('Creating cinematic tour... This may take minutes.');
      setError(null);
      try {
          const url = await generateVideo(prompt);
          setVideoUrl(url);
      } catch (err) {
        handleError(err);
      } finally {
          setIsLoading(false);
          setLoadingMessage('');
      }
  }, [handleError]);

  const handleCloseVideo = useCallback(() => {
    if (videoUrl) {
      URL.revokeObjectURL(videoUrl);
    }
    setVideoUrl(null);
  }, [videoUrl]);

  const updateRendering = useCallback(async (renderingId: string, updates: Partial<Rendering>) => {
    if (!currentDesignId) return;
    const design = savedDesigns.find(d => d.housePlan.id === currentDesignId);
    if (!design) return;

    const newRenderings = design.renderings.map(r => r.id === renderingId ? { ...r, ...updates } : r);
    const updatedDesign = { ...design, renderings: newRenderings };
    await saveDesignChange(updatedDesign);
  }, [currentDesignId, savedDesigns, saveDesignChange]);

  const deleteRenderings = useCallback(async (renderingIds: string[]) => {
    if (!currentDesignId) return;
    const design = savedDesigns.find(d => d.housePlan.id === currentDesignId);
    if (!design) return;

    if (design.accessLevel === 'view') return;

    const newRenderings = design.renderings.filter(r => !renderingIds.includes(r.id));
    const updatedDesign = { ...design, renderings: newRenderings };
    await saveDesignChange(updatedDesign);
  }, [currentDesignId, savedDesigns, saveDesignChange]);

  // NEW: Handler for reordering renderings
  const handleReorderRenderings = useCallback(async (reorderedRenderings: Rendering[]) => {
    if (!currentDesignId) return;
    const design = savedDesigns.find(d => d.housePlan.id === currentDesignId);
    if (!design) return;

    if (design.accessLevel === 'view') return;

    const updatedDesign = { ...design, renderings: reorderedRenderings };
    await saveDesignChange(updatedDesign);
  }, [currentDesignId, savedDesigns, saveDesignChange]);

  const handleSelectDesign = useCallback((designId: string) => {
    setCurrentDesignId(designId);
    setView(AppView.Results);
    setError(null);
  }, []);

  const handleDeleteDesign = useCallback(async (designId: string) => {
    const design = savedDesigns.find(d => d.housePlan.id === designId);
    if (!design) return;

    const isOwner = design.accessLevel === 'owner';
    const message = isOwner 
        ? "Are you sure you want to delete this design and all its renderings? This action cannot be undone."
        : "Remove this shared design from your list?";

    if (window.confirm(message)) {
      try {
        const userId = getUserId();

        if (isOwner) {
            await dbService.deleteDesign(designId);
            if (user && user.email !== 'anonymous') {
                await cloudService.deleteDesign(userId, designId);
            }
        } else {
            // It's a shared design, remove the share record
            if (user) {
                await cloudService.removeShare(user.email, designId);
            }
        }

        setSavedDesigns(prev => prev.filter(d => d.housePlan.id !== designId));
        if (currentDesignId === designId) {
            resetApp();
        }
      } catch (err) {
        console.error("Failed to delete design", err);
        setError("Failed to delete design.");
      }
    }
  }, [currentDesignId, resetApp, getUserId, user, savedDesigns]);

  const handleAddRoom = useCallback(async (newRoom: Room) => {
    if (!currentDesignId) return;
    const design = savedDesigns.find(d => d.housePlan.id === currentDesignId);
    if (!design) return;

    if (design.accessLevel === 'view') return;

    const updatedHousePlan = {
        ...design.housePlan,
        rooms: [...design.housePlan.rooms, newRoom]
    };
    const updatedDesign = { ...design, housePlan: updatedHousePlan };
    await saveDesignChange(updatedDesign);
  }, [currentDesignId, savedDesigns, saveDesignChange]);

  const handleSelectKey = useCallback(async () => {
      if (window.aistudio && typeof window.aistudio.openSelectKey === 'function') {
        try {
          await window.aistudio.openSelectKey();
          setIsKeyReady(true);
          checkApiKey();
        } catch (e) {
          setError("Could not open API key selection. Please try again.");
        }
      } else {
          setIsKeyReady(true);
      }
  }, [checkApiKey]);

  const handleClearError = useCallback(() => setError(null), []);

  const handleSignIn = useCallback(async () => {
      setIsLoading(true);
      setLoadingMessage("Signing in with Google...");
      try {
        await authService.signIn();
      } catch (e) {
        setError("Sign in failed. Please try again.");
      } finally {
        setIsLoading(false);
        setLoadingMessage('');
      }
  }, []);

  const handleSignInGuest = useCallback(async () => {
      setIsLoading(true);
      setLoadingMessage("Setting up Guest Account...");
      try {
        await authService.signInGuest();
      } catch (e) {
        console.error("Guest Sign In Error:", e);
        setError("Guest sign in failed. Please try again.");
      } finally {
        setIsLoading(false);
        setLoadingMessage('');
      }
  }, []);

  const handleShareDesign = useCallback(async (email: string, permission: AccessLevel) => {
      if (!currentDesignId || !user) return;

      const design = savedDesigns.find(d => d.housePlan.id === currentDesignId);
      if (!design) return;

      // Only owner can share
      if (design.accessLevel !== 'owner') {
          setError("Only the project owner can share this design.");
          return;
      }

      try {
          await cloudService.shareDesign(user.email, currentDesignId, email, permission);
      } catch (e) {
          throw e;
      }
  }, [currentDesignId, user, savedDesigns]);

  // --- RENDERING LOGIC ---

  if (isKeyReady === null || isAuthLoading) {
      return <LoadingOverlay message="Initializing..." />;
  }

  // GATEKEEPER: If no user, show Landing Page
  if (!user) {
      return (
        <>
            {isLoading && <LoadingOverlay message={loadingMessage} />}
            <LandingPage 
                onSignIn={handleSignIn} 
                onSignInGuest={handleSignInGuest}
                isKeyReady={isKeyReady !== false} 
                onSelectKey={handleSelectKey}
                error={error}
            />
        </>
      );
  }

  // MAIN APP
  return (
    <div className="min-h-screen font-sans text-gray-900 dark:text-gray-100 transition-colors duration-300">
      {isKeyReady === false && <ApiKeyPrompt onSelectKey={handleSelectKey} />}
      <Header 
        user={user}
        onSignIn={handleSignIn}
        onSignOut={handleSignOut}
        onNewDesign={resetApp}
        onSaveDesign={handleManualSaveToCloud}
        isSaving={isSavingCloud}
        hasActiveDesign={!!currentDesign}
        searchQuery={searchQuery} 
        onSearchChange={setSearchQuery} 
      />
      <main className="container mx-auto px-4 py-8">
        {isLoading && <LoadingOverlay message={loadingMessage} />}
        {view === AppView.Home && <HomePage 
            onGenerate={handleGenerationRequest} 
            error={error} 
            designs={filteredDesigns}
            onSelectDesign={handleSelectDesign}
            onDeleteDesign={handleDeleteDesign}
            onErrorClear={handleClearError}
            isKeyReady={isKeyReady}
            onSelectKey={handleSelectKey}
            user={user}
        />}
        {view === AppView.Results && currentDesign && (
          <ResultsPage
            key={currentDesign.housePlan.id}
            design={currentDesign}
            onNewRendering={handleNewRendering}
            onUpdateRendering={updateRendering}
            onDeleteRenderings={deleteRenderings}
            onGenerateVideoTour={handleGenerateVideoTour}
            onRecreateRendering={handleRecreateRendering}
            onAddRoom={handleAddRoom}
            videoUrl={videoUrl}
            onCloseVideo={handleCloseVideo}
            error={error}
            onErrorClear={handleClearError}
            isLoading={isLoading}
            isKeyReady={isKeyReady}
            onSelectKey={handleSelectKey}
            onOpenShareModal={() => setIsShareModalOpen(true)}
            onReorderRenderings={handleReorderRenderings}
          />
        )}
      </main>

      {/* Share Modal */}
      <ShareModal 
        isOpen={isShareModalOpen}
        onClose={() => setIsShareModalOpen(false)}
        onShare={handleShareDesign}
        designTitle={currentDesign?.housePlan.title || 'Project'}
      />
    </div>
  );
}

export default App;

import React, { useState, useMemo, useRef, useEffect } from 'react';
import { Rendering, Room, SavedDesign } from '../types';
import CustomizationPanel from './CustomizationPanel';
import ImageCard from './ImageCard';
import AddRoomModal from './AddRoomModal';
import { LayoutGrid, Trash2, Play, X, Video, AlertTriangle, RefreshCw, Film, PlusCircle, Settings, Music, Type, Clock, Activity, Repeat, Pause, Share2, Lock, Move } from 'lucide-react';

interface ResultsPageProps {
  design: SavedDesign;
  onNewRendering: (prompt: string, category: string) => void;
  onUpdateRendering: (id: string, updates: Partial<Rendering>) => void;
  onDeleteRenderings: (ids: string[]) => void;
  onGenerateVideoTour: (prompt: string) => void;
  onRecreateRendering: (category: string) => void;
  onAddRoom: (room: Room) => void;
  videoUrl: string | null;
  onCloseVideo: () => void;
  error: string | null;
  onErrorClear: () => void;
  isLoading: boolean;
  isKeyReady: boolean;
  onSelectKey: () => void;
  onOpenShareModal: () => void;
  onReorderRenderings: (renderings: Rendering[]) => void;
}

interface SlideshowConfig {
  duration: number;
  transition: 'fade' | 'slide' | 'zoom';
  showCaptions: boolean;
  audioFile: File | null;
  repeat: boolean;
}

const ResultsPage: React.FC<ResultsPageProps> = ({ design, onNewRendering, onUpdateRendering, onDeleteRenderings, onGenerateVideoTour, onRecreateRendering, onAddRoom, videoUrl, onCloseVideo, error, onErrorClear, isLoading, isKeyReady, onSelectKey, onOpenShareModal, onReorderRenderings }) => {
  const { housePlan, renderings, initialPrompt, accessLevel = 'owner' } = design;
  const isViewOnly = accessLevel === 'view';
  const isOwner = accessLevel === 'owner';

  const [selectedRoom, setSelectedRoom] = useState<Room | null>(housePlan.rooms[0] || null);
  const [selectedRenderings, setSelectedRenderings] = useState<string[]>([]);
  const [isAddRoomModalOpen, setIsAddRoomModalOpen] = useState(false);
  const [isReordering, setIsReordering] = useState(false);
  const [draggedRenderingIndex, setDraggedRenderingIndex] = useState<number | null>(null);

  // Slideshow State
  const [slideshowActive, setSlideshowActive] = useState(false);
  const [isPaused, setIsPaused] = useState(false);
  const [showSlideshowConfig, setShowSlideshowConfig] = useState(false);
  const [currentSlide, setCurrentSlide] = useState(0);
  const [slideshowConfig, setSlideshowConfig] = useState<SlideshowConfig>({
    duration: 5,
    transition: 'fade',
    showCaptions: true,
    audioFile: null,
    repeat: true
  });

  // Audio Ref for slideshow music
  const audioRef = useRef<HTMLAudioElement | null>(null);
  const slideTimerRef = useRef<ReturnType<typeof setInterval> | null>(null);

  const [enlargedImageUrl, setEnlargedImageUrl] = useState<string | null>(null);

  const { exteriorRooms, interiorRooms } = useMemo(() => {
    const exteriors: Room[] = [];
    const interiors: Room[] = [];
    housePlan.rooms.forEach(room => {
      if (room.name.toLowerCase().includes('exterior')) {
        exteriors.push(room);
      } else {
        interiors.push(room);
      }
    });
    return { exteriorRooms: exteriors, interiorRooms: interiors };
  }, [housePlan.rooms]);

  const likedRenderings = useMemo(() => renderings.filter(r => r.liked), [renderings]);
  const canCreateMarketingVideo = likedRenderings.length >= 10;

  // Logic: > 4 images enables basic slideshow. >= 10 enables advanced features.
  const canStartSlideshow = likedRenderings.length > 4;
  const hasAdvancedSlideshowFeatures = likedRenderings.length >= 10;

  const handleRoomSelect = (room: Room) => {
    setSelectedRoom(room);

    // Auto-generate Back Exterior if it's selected and doesn't exist yet
    // Disabled in view-only mode
    if (!isViewOnly && room.name === 'Back Exterior' && !isLoading) {
        const hasBackRendering = renderings.some(r => r.category === 'Back Exterior');
        if (!hasBackRendering) {
             const prompt = `Photorealistic 3D rendering of the BACK exterior of a ${housePlan.style} house. The overall architectural style should be consistent with this main description: "${initialPrompt}". Focus on the backyard view. Crucially, DO NOT include front-of-house elements like driveways or the street.`;
             onNewRendering(prompt, 'Back Exterior');
        }
    }
  };


  const handleSelectToggle = (id: string) => {
    setSelectedRenderings(prev =>
      prev.includes(id) ? prev.filter(pId => pId !== id) : [...prev, id]
    );
  };

  const handleSlideshowClick = () => {
      if (hasAdvancedSlideshowFeatures) {
          setShowSlideshowConfig(true);
      } else {
          // Start basic slideshow immediately
          setSlideshowConfig({
              duration: 3,
              transition: 'fade',
              showCaptions: false,
              audioFile: null,
              repeat: true
          });
          setCurrentSlide(0);
          setIsPaused(false);
          setSlideshowActive(true);
      }
  };

  const startAdvancedSlideshow = () => {
      setShowSlideshowConfig(false);
      setCurrentSlide(0);
      setIsPaused(false);
      setSlideshowActive(true);
  };

  const togglePause = (e: React.MouseEvent) => {
    e.stopPropagation();
    setIsPaused(prev => !prev);
  };

  // Helper function to gently fade out audio
  const fadeOutAudio = (audio: HTMLAudioElement, duration: number = 2000, callback?: () => void) => {
    const steps = 10; 
    const intervalTime = duration / steps;

    const startVolume = audio.volume;
    const volStep = startVolume / steps;

    const fadeOutInterval = setInterval(() => {
        if (audio.volume > volStep) {
            audio.volume = Math.max(0, audio.volume - volStep);
        } else {
            audio.volume = 0;
            audio.pause();
            clearInterval(fadeOutInterval);
            if (callback) callback();
        }
    }, intervalTime);
  };

  useEffect(() => {
    if (audioRef.current) {
        if (isPaused) {
            audioRef.current.pause();
        } else if (slideshowActive) {
            audioRef.current.play().catch(e => console.error("Audio resume failed", e));
        }
    }
  }, [isPaused, slideshowActive]);

  useEffect(() => {
      let fadeOutTimeout: ReturnType<typeof setTimeout>;

      if (slideshowActive && slideshowConfig.audioFile) {
          const audioUrl = URL.createObjectURL(slideshowConfig.audioFile);
          const audio = new Audio(audioUrl);
          audio.loop = slideshowConfig.repeat;
          audio.volume = 0; 
          audioRef.current = audio;
          audio.play().catch(e => console.error("Audio playback failed", e));

          const fadeInterval = setInterval(() => {
              if (audio.volume < 0.9) {
                  audio.volume += 0.1;
              } else {
                  audio.volume = 1;
                  clearInterval(fadeInterval);
              }
          }, 200);

          if (!slideshowConfig.repeat) {
              const slideDurationMs = slideshowConfig.duration * 1000;
              const totalSlideshowDurationMs = likedRenderings.length * slideDurationMs;
              const fadeOutStartTime = Math.max(0, totalSlideshowDurationMs - slideDurationMs); 

              fadeOutTimeout = setTimeout(() => {
                  if (audioRef.current && !audioRef.current.paused && !audioRef.current.loop) {
                      fadeOutAudio(audioRef.current, slideDurationMs);
                  }
              }, fadeOutStartTime);
          }

          return () => {
              clearInterval(fadeInterval);
              clearTimeout(fadeOutTimeout);
              URL.revokeObjectURL(audioUrl);
          };
      }
  }, [slideshowActive, slideshowConfig.audioFile, slideshowConfig.repeat, slideshowConfig.duration, likedRenderings.length]);

  useEffect(() => {
      if (slideshowActive && !isPaused) {
          slideTimerRef.current = setInterval(() => {
              nextSlide();
          }, slideshowConfig.duration * 1000);
      }
      return () => {
          if (slideTimerRef.current) clearInterval(slideTimerRef.current);
      };
  }, [slideshowActive, isPaused, slideshowConfig.duration, likedRenderings.length, slideshowConfig.repeat]);


  const closeSlideshow = () => {
    if (audioRef.current && !audioRef.current.paused) {
        fadeOutAudio(audioRef.current, 1000, () => {
             audioRef.current = null;
        });
    } else {
        audioRef.current = null;
    }
    setSlideshowActive(false);
    setIsPaused(false);
  };

  const nextSlide = () => {
    setCurrentSlide((prev) => {
        const next = prev + 1;
        if (next >= likedRenderings.length) {
            if (slideshowConfig.repeat) {
                return 0; 
            } else {
                closeSlideshow(); 
                return prev;
            }
        }
        return next;
    });
  }

  const prevSlide = (e?: React.MouseEvent) => {
    if(e) e.stopPropagation();
    setCurrentSlide((prev) => (prev - 1 + likedRenderings.length) % likedRenderings.length);
  }

  const nextSlideManual = (e?: React.MouseEvent) => {
    if(e) e.stopPropagation();
    nextSlide();
  }

  const handleBulkDelete = () => {
    if(selectedRenderings.length > 0) {
      onDeleteRenderings(selectedRenderings);
      setSelectedRenderings([]);
    }
  }

  const handleGenerateVideoClick = () => {
    const prompt = `Create a cinematic 30-second video tour of the exterior of a ${housePlan.style} house, based on the description: "${initialPrompt}". Showcase both the front and back of the house using smooth camera movements and dramatic lighting, for example during a golden hour sunset. The video should pan smoothly around the property and include an inspiring background music track.`;
    onGenerateVideoTour(prompt);
  };

  const handleGenerateMarketingVideo = () => {
      if (!canCreateMarketingVideo) return;
      const totalDuration = (likedRenderings.length * 4) + 8;
      const shotList = likedRenderings.map((rendering, index) => {
        const detailsPart = rendering.prompt.split('incorporate the following specific details for this room: ')[1]?.split('.')[0] || `a beautiful ${rendering.category}`;
        return `
---
**Shot ${index + 2}: Scene of the ${rendering.category}**
- **Duration**: 4 seconds.
- **Description**: A photorealistic view of the ${rendering.category}. It must include these specific features: ${detailsPart}. The scene should have warm, natural lighting and a luxurious feel.
- **Camera Movement**: Use a slow, subtle camera movement (e.g., pan left, dolly in, gentle zoom).
---
`;
      }).join('');

      const prompt = `
You are a professional video director creating a high-end, cinematic real estate marketing video for "C&SH Group Properties, LLC".
**CRITICAL INSTRUCTIONS:**
1.  **Total Duration:** The final video MUST be exactly **${totalDuration} seconds** long.
2.  **Structure:** The video must follow the precise SHOT LIST provided below.
3.  **Pacing:** Each scene described in the shot list must be exactly 4 seconds long.
4.  **Music:** The video must have an inspiring, sophisticated, and instrumental background music track appropriate for a luxury property tour. The music must gently start to fade out 8 seconds before the end of the video.
5.  **Quality:** All scenes must be photorealistic, with high-end architectural visualization and cinematic lighting.
**--- SHOT LIST ---**
---
**Shot 1: Title Card**
- **Duration**: 4 seconds.
- **Content**: Display the text "${housePlan.title}" in an elegant, minimal font on a clean, professional background.
---
${shotList}
---
**Shot ${likedRenderings.length + 2}: Outro Card**
- **Duration**: 4 seconds.
- **Content**: Display the company name "C&SH Group Properties, LLC" and a contact number "(555) 123-4567". Match the style of the title card.
---
`;
      onGenerateVideoTour(prompt);
  };

  const handleEnlarge = (imageUrl: string) => {
    setEnlargedImageUrl(imageUrl);
  };

  const handleCloseEnlarged = () => {
    setEnlargedImageUrl(null);
  };

  const getSmartCaption = (rendering: Rendering) => {
      if (!rendering.prompt) return `A professional visualization of the ${rendering.category}.`;

      const detailsRegex = /incorporate the following (?:specific )?details.*?: (.*?)(?:\.|$| Crucially)/i;
      const detailsMatch = rendering.prompt.match(detailsRegex);

      if (detailsMatch && detailsMatch[1] && detailsMatch[1].trim().length > 5) {
          const details = detailsMatch[1].trim();
          return `${rendering.category} designed ${details}.`;
      }
      const conceptRegex = /(?:concept|description)(?: is|): "(.*?)"/i;
      const conceptMatch = rendering.prompt.match(conceptRegex);
      if (conceptMatch && conceptMatch[1]) {
           let concept = conceptMatch[1].trim();
           if (concept.length > 120) concept = concept.substring(0, 117) + '...';
           return `${rendering.category}: ${concept}`;
      }
      return `A stunning 3D visualization of the ${rendering.category}.`;
  };

  const getTransitionClass = () => {
      switch(slideshowConfig.transition) {
          case 'slide': return 'transition-transform duration-700 ease-in-out';
          case 'zoom': return 'transition-transform duration-1000 ease-in-out scale-105';
          case 'fade': default: return 'transition-opacity duration-1000 ease-in-out';
      }
  };

  // Reorder Logic
  const handleDragStart = (e: React.DragEvent, index: number) => {
    setDraggedRenderingIndex(index);
    e.dataTransfer.effectAllowed = "move";
    // Optional: Set a drag image here if desired
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    e.dataTransfer.dropEffect = "move";
  };

  const handleDrop = (e: React.DragEvent, targetIndex: number) => {
    e.preventDefault();
    if (draggedRenderingIndex === null || draggedRenderingIndex === targetIndex) return;

    const newRenderings = [...renderings];
    const [movedItem] = newRenderings.splice(draggedRenderingIndex, 1);
    newRenderings.splice(targetIndex, 0, movedItem);

    onReorderRenderings(newRenderings);
    setDraggedRenderingIndex(null);
  };

  const selectedCategory = selectedRoom?.name;
  const canRecreate = selectedCategory && (selectedCategory === 'Front Exterior' || selectedCategory === 'Back Exterior');
  const hasRenderingForSelected = canRecreate ? renderings.some(r => r.category === selectedCategory) : false;

  return (
    <div>
      <div className="text-center mb-8 relative">
        <h2 className="text-3xl md:text-4xl font-bold text-gray-800 dark:text-white flex items-center justify-center gap-3">
            {housePlan.title}
            {isViewOnly && <Lock className="h-6 w-6 text-gray-400" title="View Only" />}
        </h2>
        <p className="text-lg text-brand-600 dark:text-brand-400 font-medium mt-1">{housePlan.style}</p>

        {isOwner && (
            <div className="absolute top-0 right-0">
                 <button 
                  onClick={onOpenShareModal}
                  className="flex items-center gap-2 px-4 py-2 text-sm font-medium text-brand-600 bg-white border border-brand-200 rounded-full hover:bg-brand-50 shadow-sm transition-colors"
                >
                    <Share2 className="h-4 w-4" /> Share
                </button>
            </div>
        )}
      </div>

      {error && (
        <div className="mb-6 flex items-center justify-between p-4 text-sm text-red-800 rounded-lg bg-red-50 dark:bg-gray-800 dark:text-red-400" role="alert">
            <div className="flex items-center">
                <AlertTriangle className="flex-shrink-0 inline w-5 h-5 mr-3" />
                <div>
                    <span className="font-medium">Error:</span> {error}
                </div>
            </div>
            <button onClick={onErrorClear} className="p-1.5 rounded-full hover:bg-red-100 dark:hover:bg-gray-700" aria-label="Dismiss error">
                <X className="h-4 w-4"/>
            </button>
        </div>
      )}

      {isViewOnly && (
         <div className="mb-6 p-3 bg-blue-50 dark:bg-blue-900/20 text-blue-700 dark:text-blue-300 rounded-lg text-center text-sm">
             You are viewing this project in <strong>Read-Only Mode</strong>. Editing and generation are disabled.
         </div>
      )}

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* Column 1: Room List */}
        <div className="lg:col-span-2 bg-white dark:bg-gray-800 p-4 rounded-lg shadow-md h-fit sticky top-24">
          <h3 className="font-bold text-lg mb-2">Exterior</h3>
          <ul className="mb-4">
            {exteriorRooms.map(room => (
              <li key={room.name}>
                <button
                  onClick={() => handleRoomSelect(room)}
                  className={`w-full text-left px-3 py-2 rounded-md text-sm font-medium transition-colors ${
                    selectedRoom?.name === room.name
                      ? 'bg-brand-100 text-brand-700 dark:bg-brand-900 dark:text-brand-200'
                      : 'hover:bg-gray-100 dark:hover:bg-gray-700'
                  }`}
                >
                  {room.name}
                </button>
              </li>
            ))}
          </ul>

          <h3 className="font-bold text-lg mb-2 flex items-center gap-2 pt-4 border-t border-gray-200 dark:border-gray-700"><LayoutGrid className="h-5 w-5 text-brand-500"/> Rooms</h3>
          <ul>
            {interiorRooms.map(room => (
              <li key={room.name}>
                <button
                  onClick={() => handleRoomSelect(room)}
                  className={`w-full text-left px-3 py-2 rounded-md text-sm font-medium transition-colors ${
                    selectedRoom?.name === room.name
                      ? 'bg-brand-100 text-brand-700 dark:bg-brand-900 dark:text-brand-200'
                      : 'hover:bg-gray-100 dark:hover:bg-gray-700'
