import React, { useState, useRef, useCallback } from 'react';
import { Mic, Upload, Sparkles, AlertTriangle, HelpCircle, X, Trash2, KeyRound } from 'lucide-react';
import { SavedDesign, User } from '../types';

interface UploadedFiles {
    frontPlan: File | null;
    backPlan: File | null;
    facadeImage: File | null;
}

interface HomePageProps {
  onGenerate: (description: string, files: UploadedFiles) => void;
  error: string | null;
  designs: SavedDesign[];
  onSelectDesign: (designId: string) => void;
  onDeleteDesign: (designId: string) => void;
  onErrorClear: () => void;
  isKeyReady: boolean;
  onSelectKey: () => void;
  user: User | null;
}

// Memoized component for displaying a single design card.
const DesignCard = React.memo(({ design, onSelect, onDelete }: { design: SavedDesign, onSelect: (id: string) => void, onDelete: (id: string) => void }) => {
    return (
        <div
            role="button"
            tabIndex={0}
            onClick={() => onSelect(design.housePlan.id)}
            onKeyDown={(e) => e.key === 'Enter' && onSelect(design.housePlan.id)}
            className="group bg-white dark:bg-gray-800 rounded-lg shadow-md hover:shadow-xl transition-all duration-300 cursor-pointer border dark:border-gray-700 hover:border-brand-500 dark:hover:border-brand-400 flex flex-col justify-between"
        >
            <div className="p-4">
                <h4 className="font-bold text-lg text-gray-800 dark:text-white truncate group-hover:text-brand-700 dark:group-hover:text-brand-300">{design.housePlan.title}</h4>
                <p className="text-sm text-brand-600 dark:text-brand-400 font-medium">{design.housePlan.style}</p>
                <p className="text-sm text-gray-600 dark:text-gray-300 mt-2 line-clamp-2">{design.initialPrompt}</p>
            </div>
            <div className="p-3 bg-gray-50 dark:bg-gray-800/50 border-t dark:border-gray-700 mt-auto flex items-center justify-between">
                <span className="text-xs text-gray-500 dark:text-gray-400">
                    {new Date(design.housePlan.createdAt).toLocaleDateString()}
                </span>
                <button
                    onClick={(e) => {
                        e.stopPropagation();
                        onDelete(design.housePlan.id);
                    }}
                    className="flex items-center justify-center gap-1.5 px-3 py-1 text-xs font-medium text-red-600 dark:text-red-400 hover:bg-red-100 dark:hover:bg-red-900/50 rounded-md transition-colors"
                    aria-label={`Delete design: ${design.housePlan.title}`}
                >
                    <Trash2 className="h-4 w-4" />
                    Delete
                </button>
            </div>
        </div>
    );
});

// Memoized list component.
const DesignList = React.memo(({ designs, onSelectDesign, onDeleteDesign }: { designs: SavedDesign[], onSelectDesign: (id: string) => void, onDeleteDesign: (id: string) => void }) => {
    if (designs.length === 0) {
        return (
            <div className="text-center py-10 px-6 bg-white dark:bg-gray-800 rounded-lg shadow-md">
                <h4 className="text-lg font-semibold text-gray-700 dark:text-gray-200">
                    No designs found.
                </h4>
                <p className="mt-2 text-gray-500 dark:text-gray-400">
                    Create your first design using the form above to get started!
                </p>
            </div>
        );
    }

    return (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {designs.map(design => (
                <DesignCard
                    key={design.housePlan.id}
                    design={design}
                    onSelect={onSelectDesign}
                    onDelete={onDeleteDesign}
                />
            ))}
        </div>
    );
});

const HomePage: React.FC<HomePageProps> = ({ onGenerate, error, designs, onSelectDesign, onDeleteDesign, onErrorClear, isKeyReady, onSelectKey, user }) => {
  const [description, setDescription] = useState('');
  const [frontPlan, setFrontPlan] = useState<File | null>(null);
  const [backPlan, setBackPlan] = useState<File | null>(null);
  const [facadeImage, setFacadeImage] = useState<File | null>(null);
  const [isListening, setIsListening] = useState(false);
  const [showHowTo, setShowHowTo] = useState(false);

  const frontPlanInputRef = useRef<HTMLInputElement>(null);
  const backPlanInputRef = useRef<HTMLInputElement>(null);
  const facadeImageInputRef = useRef<HTMLInputElement>(null);

  const handleFrontPlanChange = useCallback((event: React.ChangeEvent<HTMLInputElement>) => {
    if (event.target.files && event.target.files[0]) {
      setFrontPlan(event.target.files[0]);
    } else {
      setFrontPlan(null);
    }
  }, []);

  const handleBackPlanChange = useCallback((event: React.ChangeEvent<HTMLInputElement>) => {
    if (event.target.files && event.target.files[0]) {
      setBackPlan(event.target.files[0]);
    } else {
      setBackPlan(null);
    }
  }, []);

  const handleFacadeImageChange = useCallback((event: React.ChangeEvent<HTMLInputElement>) => {
    if (event.target.files && event.target.files[0]) {
      setFacadeImage(event.target.files[0]);
    } else {
      setFacadeImage(null);
    }
  }, []);

  const handleDescriptionChange = useCallback((e: React.ChangeEvent<HTMLTextAreaElement>) => {
    setDescription(e.target.value);
  }, []);

  const handleGenerateClick = useCallback(() => {
    if (description.trim() || frontPlan || backPlan || facadeImage) {
      onGenerate(description, { frontPlan, backPlan, facadeImage });
    }
  }, [description, frontPlan, backPlan, facadeImage, onGenerate]);

  const handleVoiceInput = useCallback(() => {
    const recognition = new ((window as any).SpeechRecognition || (window as any).webkitSpeechRecognition)();
    if (!recognition) {
        alert("Speech recognition not supported in this browser.");
        return;
    }

    recognition.lang = 'en-US';
    recognition.interimResults = false;
    recognition.maxAlternatives = 1;

    if (isListening) {
        recognition.stop();
        setIsListening(false);
        return;
    }

    recognition.start();
    setIsListening(true);

    recognition.onresult = (event: any) => {
        const speechResult = event.results[0][0].transcript;
        setDescription(prev => prev ? `${prev} ${speechResult}`: speechResult);
    };

    recognition.onspeechend = () => {
        recognition.stop();
        setIsListening(false);
    };

    recognition.onerror = (event: any) => {
        console.error('Speech recognition error', event.error);
        setIsListening(false);
    };
  }, [isListening]);

  return (
    <div className="flex flex-col items-center justify-center py-12">
      {showHowTo && (
        <div 
            className="fixed inset-0 bg-black bg-opacity-50 z-50 flex items-center justify-center p-4"
            onClick={() => setShowHowTo(false)}
            role="dialog"
            aria-modal="true"
            aria-labelledby="how-to-title"
        >
            <div 
                className="bg-white dark:bg-gray-800 rounded-lg shadow-xl w-full max-w-2xl"
                onClick={(e) => e.stopPropagation()}
            >
                <div className="flex justify-between items-center p-4 border-b dark:border-gray-700">
                    <h2 id="how-to-title" className="text-xl font-bold flex items-center gap-2">
                        <HelpCircle className="text-brand-600 dark:text-brand-400" />
                        How to Get the Best Results
                    </h2>
                    <button onClick={() => setShowHowTo(false)} className="p-2 rounded-full hover:bg-gray-200 dark:hover:bg-gray-700" aria-label="Close">
                        <X className="h-5 w-5" />
                    </button>
                </div>
                <div className="p-6 max-h-[70vh] overflow-y-auto">
                    <div className="space-y-4 text-gray-700 dark:text-gray-300">
                        <div>
                            <h3 className="font-semibold text-lg text-gray-800 dark:text-white mb-2">1. Write a Great Description</h3>
                            <p className="mb-2">The quality of your initial description is key. Be descriptive but concise. Think like you're talking to an architect.</p>
                            <ul className="list-disc list-inside space-y-1 pl-2">
                                <li><strong>Start with the big picture:</strong> Begin with the overall style and size.
                                    <p className="text-sm text-gray-500 dark:text-gray-400 pl-4"><em>e.g., "A sprawling single-story mid-century modern home" or "A cozy two-story colonial revival house with a symmetrical facade."</em></p>
                                </li>
                                <li><strong>Mention key features:</strong> Call out important architectural elements.
                                    <p className="text-sm text-gray-500 dark:text-gray-400 pl-4"><em>e.g., "...with a large wrap-around porch," "...featuring floor-to-ceiling windows," "...a gabled roof with dormers."</em></p>
                                </li>
                                <li><strong>List important rooms:</strong> Tell the AI what spaces are most important to you.
                                    <p className="text-sm text-gray-500 dark:text-gray-400 pl-4"><em>e.g., "...an open-concept kitchen and living area, a dedicated home office, and a master suite with a private balcony."</em></p>
                                </li>
                                <li><strong>Add material/color details:</strong> If you have a vision, share it.
                                    <p className="text-sm text-gray-500 dark:text-gray-400 pl-4"><em>e.g., "The exterior is white brick with black trim," "...dark hardwood floors throughout the main level."</em></p>
                                </li>
                            </ul>
                        </div>
                        <div>
                            <h3 className="font-semibold text-lg text-gray-800 dark:text-white mb-2">2. Upload Plans & Images (Optional)</h3>
                            <p>Supplement your description by uploading images. Clear, high-contrast images work best.</p>
                             <ul className="list-disc list-inside space-y-1 pl-2">
                                <li><strong>Architectural Plans:</strong> Upload front and back floor plans for the AI to understand the layout.</li>
                                <li><strong>Example Facade:</strong> Upload a photo of a house you like. The AI will use it as a primary style reference for the initial 3D rendering.</li>
                            </ul>
                        </div>
                         <div>
                            <h3 className="font-semibold text-lg text-gray-800 dark:text-white mb-2">3. Generate & Customize</h3>
                            <p>After the initial generation, you'll land on the results page. From there, you can:</p>
                            <ul className="list-disc list-inside space-y-1 pl-2">
                                <li>Select different rooms from the list on the left.</li>
                                <li>Use the customization panel on the right to fine-tune details.</li>
                                <li>Generate new, specific renderings for each room to fully visualize your design.</li>
                            </ul>
                        </div>
                        <div>
                            <h3 className="font-semibold text-lg text-gray-800 dark:text-white mb-2">4. Share & Collaborate</h3>
                            <p>Once you are happy with your designs:</p>
                            <ul className="list-disc list-inside space-y-1 pl-2">
                                <li>Use the <strong>Share</strong> button to send your project to others via email.</li>
                                <li>Grant <strong>View</strong> access for feedback or <strong>Edit</strong> access to collaborate on the design.</li>
                            </ul>
                        </div>
                         <div className="pt-4 mt-4 border-t border-gray-200 dark:border-gray-600">
                            <h3 className="font-semibold text-lg text-red-600 dark:text-red-400 mb-2 flex items-center gap-2"><AlertTriangle/> Important: Content Policy</h3>
                            <p>This is a professional architectural design tool. Any attempt to generate pornographic, nude, or sexually explicit content is a violation of our terms of service. All prompts are monitored. Violators will have their access permanently revoked without warning.</p>
                        </div>
                    </div>
                </div>
                 <div className="p-4 border-t dark:border-gray-700 text-right">
                    <button 
                        onClick={() => setShowHowTo(false)}
                        className="px-4 py-2 bg-brand-600 text-white rounded-md hover:bg-brand-700"
                    >
                        Got it!
                    </button>
                </div>
            </div>
        </div>
      )}
      <div className="w-full max-w-3xl text-center">
        <h2 className="text-3xl md:text-5xl font-extrabold text-gray-800 dark:text-white">
          {user ? `Welcome back, ${user.name}!` : "Design Your Dream Home with AI"}
        </h2>
        <p className="mt-4 text-lg text-gray-600 dark:text-gray-300">
          Describe your vision, upload a floor plan, or use your voice. Let our AI architect bring your ideas to life.
        </p>
      </div>

      <div className="mt-10 w-full max-w-3xl bg-white dark:bg-gray-800 p-6 sm:p-8 rounded-2xl shadow-lg">
        <div className="relative">
            {isKeyReady === false && (
                <div className="absolute inset-0 bg-white/80 dark:bg-gray-800/80 z-10 flex flex-col items-center justify-center p-4 rounded-2xl text-center">
                    <KeyRound className="h-8 w-8 text-brand-600 dark:text-brand-400 mx-auto" />
                    <h3 className="mt-2 text-lg font-bold text-gray-900 dark:text-white">API Key Required</h3>
                    <p className="mt-1 text-sm text-gray-600 dark:text-gray-300">
                        Please select a billing-enabled API key to generate new designs.
                    </p>
                    <button
                        onClick={onSelectKey}
                        className="mt-4 inline-flex justify-center rounded-md border border-transparent shadow-sm px-4 py-2 bg-brand-600 text-base font-medium text-white hover:bg-brand-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-brand-500 sm:text-sm"
                    >
                        Select API Key
                    </button>
                    <a
                      href="https://ai.google.dev/gemini-api/docs/billing"
                      target="_blank"
                      rel="noopener noreferrer"
                      className="mt-2 block text-xs text-brand-600 dark:text-brand-400 hover:underline"
                    >
                      Learn more about billing
                    </a>
                </div>
            )}
            {error && (
                <div className="mb-4 flex items-center justify-between p-4 text-sm text-red-800 rounded-lg bg-red-50 dark:bg-gray-700 dark:text-red-400" role="alert">
                    <div className='flex items-center'>
                        <AlertTriangle className="flex-shrink-0 inline w-4 h-4 mr-3" />
                        <span className="font-medium">Error:</span> {error}
                    </div>
                    <button onClick={onErrorClear} className="p-1.5 rounded-full hover:bg-red-100 dark:hover:bg-gray-700" aria-label="Dismiss error">
                        <X className="h-4 w-4"/>
                    </button>
                </div>
            )}
            <div className="relative">
              <textarea
                value={description}
                onChange={handleDescriptionChange}
                placeholder="e.g., A two-story modern farmhouse with a wrap-around porch, open-concept living area, and a large kitchen island..."
                className="w-full h-40 p-4 pr-12 text-base text-gray-700 dark:text-gray-200 bg-gray-50 dark:bg-gray-700 border border-gray-300 dark:border-gray-600 rounded-lg focus:ring-2 focus:ring-brand-500 focus:border-brand-500 transition"
                disabled={!isKeyReady}
              />
              <button 
                onClick={handleVoiceInput}
                className={`absolute top-3 right-3 p-2 rounded-full transition-colors ${isListening ? 'bg-red-500 text-white' : 'hover:bg-gray-200 dark:hover:bg-gray-600'}`}
                title="Use Voice Prompt"
                disabled={!isKeyReady}
                >
                <Mic className="h-5 w-5" />
              </button>
            </div>

            <div className="mt-6 w-full space-y-3">
                <div className="flex flex-col sm:flex-row items-center justify-between gap-2 p-3 bg-gray-50 dark:bg-gray-700/50 rounded-md border border-gray-200 dark:border-gray-700">
                    <span className="font-medium text-sm text-gray-700 dark:text-gray-300">Front Architectural Plan</span>
                    <div className="flex items-center gap-3">
                        {frontPlan && <span className="text-sm text-gray-500 dark:text-gray-400 truncate max-w-xs">{frontPlan.name}</span>}
                        <button onClick={() => frontPlanInputRef.current?.click()} className="flex-shrink-0 flex items-center justify-center gap-2 px-3 py-1.5 text-xs font-medium text-brand-700 bg-brand-100 dark:bg-brand-900 dark:text-brand-300 rounded-md hover:bg-brand-200 dark:hover:bg-brand-800 transition-colors" disabled={!isKeyReady}>
                            <Upload className="h-4 w-4" />
                            <span>{frontPlan ? "Change" : "Upload"}</span>
                        </button>
                        <input type="file" ref={frontPlanInputRef} onChange={handleFrontPlanChange} className="hidden" accept="image/*"/>
                    </div>
                </div>
                <div className="flex flex-col sm:flex-row items-center justify-between gap-2 p-3 bg-gray-50 dark:bg-gray-700/50 rounded-md border border-gray-200 dark:border-gray-700">
                    <span className="font-medium text-sm text-gray-700 dark:text-gray-300">Back Architectural Plan</span>
                    <div className="flex items-center gap-3">
                        {backPlan && <span className="text-sm text-gray-500 dark:text-gray-400 truncate max-w-xs">{backPlan.name}</span>}
                        <button onClick={() => backPlanInputRef.current?.click()} className="flex-shrink-0 flex items-center justify-center gap-2 px-3 py-1.5 text-xs font-medium text-brand-700 bg-brand-100 dark:bg-brand-900 dark:text-brand-300 rounded-md hover:bg-brand-200 dark:hover:bg-brand-800 transition-colors" disabled={!isKeyReady}>
                            <Upload className="h-4 w-4" />
                            <span>{backPlan ? "Change" : "Upload"}</span>
                        </button>
                        <input type="file" ref={backPlanInputRef} onChange={handleBackPlanChange} className="hidden" accept="image/*"/>
                    </div>
                </div>
                 <div className="flex flex-col sm:flex-row items-center justify-between gap-2 p-3 bg-gray-50 dark:bg-gray-700/50 rounded-md border border-gray-200 dark:border-gray-700">
                    <span className="font-medium text-sm text-gray-700 dark:text-gray-300">Example Facade of Property</span>
                    <div className="flex items-center gap-3">
                        {facadeImage && <span className="text-sm text-gray-500 dark:text-gray-400 truncate max-w-xs">{facadeImage.name}</span>}
                        <button onClick={() => facadeImageInputRef.current?.click()} className="flex-shrink-0 flex items-center justify-center gap-2 px-3 py-1.5 text-xs font-medium text-brand-700 bg-brand-100 dark:bg-brand-900 dark:text-brand-300 rounded-md hover:bg-brand-200 dark:hover:bg-brand-800 transition-colors" disabled={!isKeyReady}>
                            <Upload className="h-4 w-4" />
                            <span>{facadeImage ? "Change" : "Upload"}</span>
                        </button>
                        <input type="file" ref={facadeImageInputRef} onChange={handleFacadeImageChange} className="hidden" accept="image/*"/>
                    </div>
                </div>
            </div>

            <div className="mt-6 flex flex-col sm:flex-row items-center justify-between gap-4">
                <button
                    type="button"
                    onClick={() => setShowHowTo(true)}
                    className="flex items-center gap-1.5 px-3 py-2 text-sm font-medium text-gray-600 dark:text-gray-300 hover:text-brand-600 dark:hover:text-brand-400 transition-colors"
                    title="How to use the app"
                >
                    <HelpCircle className="h-4 w-4" />
                    <span className="hidden sm:inline">How To Use</span>
                </button>
                <button
                    onClick={handleGenerateClick}
                    disabled={!isKeyReady || (!description.trim() && !frontPlan && !backPlan && !facadeImage)}
                    className="flex items-center justify-center gap-2 px-6 py-3 text-base font-semibold text-white bg-brand-600 rounded-md hover:bg-brand-700 disabled:bg-gray-400 disabled:cursor-not-allowed transition-all shadow-md hover:shadow-lg"
                >
                    <Sparkles className="h-5 w-5" />
                    Generate
                </button>
            </div>
        </div>
      </div>

      <div className="mt-8 w-full max-w-3xl flex items-start p-4 text-sm text-yellow-800 rounded-lg bg-yellow-50 dark:bg-gray-800 dark:text-yellow-300" role="alert">
        <AlertTriangle className="flex-shrink-0 inline w-4 h-4 mr-3 mt-0.5" />
        <div>
          <span className="font-medium">Usage Policy:</span> This application is strictly for architectural and interior design purposes. Generating images of a sexually explicit, nude, or adult nature is prohibited. Violations will be logged and may lead to permanent suspension of access.
        </div>
      </div>

      <div className="mt-12 w-full max-w-5xl">
        <h3 className="text-2xl font-bold text-gray-800 dark:text-white mb-6 text-center">Your Saved Designs</h3>
        <DesignList 
            designs={designs} 
            onSelectDesign={onSelectDesign} 
            onDeleteDesign={onDeleteDesign} 
        />
      </div>
    </div>
  );
};

export default HomePage;

import React from 'react';
import { Rendering } from '../types';
import { Heart, Star, Download, Send, CheckSquare, Square, ZoomIn } from 'lucide-react';

interface ImageCardProps {
  rendering: Rendering;
  onUpdate: (id: string, updates: Partial<Rendering>) => void;
  isSelected: boolean;
  onSelectToggle: (id: string) => void;
  onEnlarge: (imageUrl: string) => void;
}

const ImageCard: React.FC<ImageCardProps> = ({ rendering, onUpdate, isSelected, onSelectToggle, onEnlarge }) => {
  const { id, category, imageUrl, liked, favorited } = rendering;

  const handleLike = () => onUpdate(id, { liked: !liked });
  const handleFavorite = () => onUpdate(id, { favorited: !favorited });

  const handleDownload = () => {
    if (!liked) {
      alert("Please 'Like' the rendering to enable download.");
      return;
    }
    const link = document.createElement('a');
    link.href = imageUrl;
    link.download = `${category.replace(/\s+/g, '_')}_${id.substring(0, 6)}.jpg`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  }

  const handleEmail = async () => {
    if (!liked) {
      alert("Please 'Like' the rendering to enable email sharing.");
      return;
    }

    const fileName = `${category.replace(/\s+/g, '_')}_${id.substring(0, 6)}.jpg`;

    try {
      // Fetch the blob from data URI
      const response = await fetch(imageUrl);
      const blob = await response.blob();
      const file = new File([blob], fileName, { type: 'image/jpeg' });

      // Check if Web Share API is available and supports file sharing
      if (navigator.canShare && navigator.canShare({ files: [file] })) {
        await navigator.share({
          files: [file],
          title: `Architectural Rendering: ${category}`,
          text: `Check out this ${category} rendering I created with Architect 3D!`,
        });
      } else {
        // Fallback: Trigger download and open mailto
        handleDownload();
        const subject = encodeURIComponent(`Architectural Rendering: ${category}`);
        const body = encodeURIComponent(`Hello,\n\nI've attached the architectural rendering for the ${category}.\n\n(Note: If the file didn't attach automatically, please attach the recently downloaded file: ${fileName})\n\nSent via Architect 3D Home Modeler.`);
        window.location.href = `mailto:?subject=${subject}&body=${body}`;
      }
    } catch (err) {
      console.error("Error sharing rendering:", err);
      alert("Failed to share image. Please try downloading it manually.");
    }
  }

  return (
    <div className={`group relative bg-white dark:bg-gray-800 rounded-lg shadow-md overflow-hidden border-2 ${isSelected ? 'border-brand-500' : 'border-transparent'}`}>
      <img src={imageUrl} alt={`Rendering of ${category}`} className="w-full h-64 object-cover" />

      <div
        role="button"
        tabIndex={0}
        onClick={() => onEnlarge(imageUrl)}
        onKeyDown={(e) => e.key === 'Enter' && onEnlarge(imageUrl)}
        className="absolute top-0 left-0 w-full h-64 bg-black bg-opacity-0 group-hover:bg-opacity-50 flex items-center justify-center cursor-pointer transition-all duration-300"
        aria-label={`Enlarge rendering of ${category}`}
      >
        <ZoomIn className="h-12 w-12 text-white opacity-0 group-hover:opacity-100 transition-opacity duration-300" />
      </div>

      <div className="absolute top-2 right-2 z-10 flex flex-col gap-2">
         <button onClick={() => onSelectToggle(id)} className="p-2 bg-black bg-opacity-50 text-white rounded-full hover:bg-opacity-75 transition-opacity">
            {isSelected ? <CheckSquare className="h-5 w-5 text-brand-400"/> : <Square className="h-5 w-5"/>}
        </button>
      </div>

      <div className="p-4">
        <h4 className="font-bold text-lg">{category}</h4>
        <div className="mt-3 flex items-center justify-between">
          <div className="flex items-center space-x-2">
            <button onClick={handleLike} className={`p-2 rounded-full hover:bg-red-100 dark:hover:bg-red-900/50 transition-colors ${liked ? 'text-red-500' : 'text-gray-400'}`}>
              <Heart className="h-5 w-5" />
            </button>
            <button onClick={handleFavorite} className={`p-2 rounded-full hover:bg-yellow-100 dark:hover:bg-yellow-900/50 transition-colors ${favorited ? 'text-yellow-400' : 'text-gray-400'}`}>
              <Star className="h-5 w-5" />
            </button>
          </div>
          <div className="flex items-center space-x-2">
             <button onClick={handleDownload} disabled={!liked} className="p-2 rounded-full text-gray-400 hover:bg-gray-200 dark:hover:bg-gray-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors" title="Download Image">
                <Download className="h-5 w-5" />
            </button>
            <button onClick={handleEmail} disabled={!liked} className="p-2 rounded-full text-gray-400 hover:bg-gray-200 dark:hover:bg-gray-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors" title="Email Image">
                <Send className="h-5 w-5" />
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ImageCard;

import React, { useState, useMemo, useRef, useEffect } from 'react';
import { Rendering, Room, SavedDesign } from '../types';
import CustomizationPanel from './CustomizationPanel';
import ImageCard from './ImageCard';
import AddRoomModal from './AddRoomModal';
import { LayoutGrid, Trash2, Play, X, Video, AlertTriangle, RefreshCw, Film, PlusCircle, Settings, Music, Type, Clock, Activity, Repeat, Pause, Share2, Lock, Move, Send } from 'lucide-react';
import JSZip from 'jszip';

interface ResultsPageProps {
  design: SavedDesign;
  onNewRendering: (prompt: string, category: string) => void;
  onUpdateRendering: (id: string, updates: Partial<Rendering>) => void;
  onDeleteRenderings: (ids: string[]) => void;
  onGenerateVideoTour: (prompt: string) => void;
  onRecreateRendering: (category: string) => void;
  onAddRoom: (room: Room) => void;
  videoUrl: string | null;
  onCloseVideo: () => void;
  error: string | null;
  onErrorClear: () => void;
  isLoading: boolean;
  isKeyReady: boolean;
  onSelectKey: () => void;
  onOpenShareModal: () => void;
  onReorderRenderings: (renderings: Rendering[]) => void;
}

interface SlideshowConfig {
  duration: number;
  transition: 'fade' | 'slide' | 'zoom';
  showCaptions: boolean;
  audioFile: File | null;
  repeat: boolean;
}

const ResultsPage: React.FC<ResultsPageProps> = ({ design, onNewRendering, onUpdateRendering, onDeleteRenderings, onGenerateVideoTour, onRecreateRendering, onAddRoom, videoUrl, onCloseVideo, error, onErrorClear, isLoading, isKeyReady, onSelectKey, onOpenShareModal, onReorderRenderings }) => {
  const { housePlan, renderings, initialPrompt, accessLevel = 'owner' } = design;
  const isViewOnly = accessLevel === 'view';
  const isOwner = accessLevel === 'owner';

  const [selectedRoom, setSelectedRoom] = useState<Room | null>(housePlan.rooms[0] || null);
  const [selectedRenderings, setSelectedRenderings] = useState<string[]>([]);
  const [isAddRoomModalOpen, setIsAddRoomModalOpen] = useState(false);
  const [isReordering, setIsReordering] = useState(false);
  const [draggedRenderingIndex, setDraggedRenderingIndex] = useState<number | null>(null);

  // Slideshow State
  const [slideshowActive, setSlideshowActive] = useState(false);
  const [isPaused, setIsPaused] = useState(false);
  const [showSlideshowConfig, setShowSlideshowConfig] = useState(false);
  const [currentSlide, setCurrentSlide] = useState(0);
  const [slideshowConfig, setSlideshowConfig] = useState<SlideshowConfig>({
    duration: 5,
    transition: 'fade',
    showCaptions: true,
    audioFile: null,
    repeat: true
  });

  // Audio Ref for slideshow music
  const audioRef = useRef<HTMLAudioElement | null>(null);
  const slideTimerRef = useRef<ReturnType<typeof setInterval> | null>(null);

  const [enlargedImageUrl, setEnlargedImageUrl] = useState<string | null>(null);

  const { exteriorRooms, interiorRooms } = useMemo(() => {
    const exteriors: Room[] = [];
    const interiors: Room[] = [];
    housePlan.rooms.forEach(room => {
      if (room.name.toLowerCase().includes('exterior')) {
        exteriors.push(room);
      } else {
        interiors.push(room);
      }
    });
    return { exteriorRooms: exteriors, interiorRooms: interiors };
  }, [housePlan.rooms]);

  const likedRenderings = useMemo(() => renderings.filter(r => r.liked), [renderings]);
  const canCreateMarketingVideo = likedRenderings.length >= 10;

  const canStartSlideshow = likedRenderings.length > 4;
  const hasAdvancedSlideshowFeatures = likedRenderings.length >= 10;

  const handleRoomSelect = (room: Room) => {
    setSelectedRoom(room);

    if (!isViewOnly && room.name === 'Back Exterior' && !isLoading) {
        const hasBackRendering = renderings.some(r => r.category === 'Back Exterior');
        if (!hasBackRendering) {
             const prompt = `Photorealistic 3D rendering of the BACK exterior of a ${housePlan.style} house. The overall architectural style should be consistent with this main description: "${initialPrompt}". Focus on the backyard view. Crucially, DO NOT include front-of-house elements like driveways or the street.`;
             onNewRendering(prompt, 'Back Exterior');
        }
    }
  };


  const handleSelectToggle = (id: string) => {
    setSelectedRenderings(prev =>
      prev.includes(id) ? prev.filter(pId => pId !== id) : [...prev, id]
    );
  };

  const handleSlideshowClick = () => {
      if (hasAdvancedSlideshowFeatures) {
          setShowSlideshowConfig(true);
      } else {
          setSlideshowConfig({
              duration: 3,
              transition: 'fade',
              showCaptions: false,
              audioFile: null,
              repeat: true
          });
          setCurrentSlide(0);
          setIsPaused(false);
          setSlideshowActive(true);
      }
  };

  const startAdvancedSlideshow = () => {
      setShowSlideshowConfig(false);
      setCurrentSlide(0);
      setIsPaused(false);
      setSlideshowActive(true);
  };

  const togglePause = (e: React.MouseEvent) => {
    e.stopPropagation();
    setIsPaused(prev => !prev);
  };

  const fadeOutAudio = (audio: HTMLAudioElement, duration: number = 2000, callback?: () => void) => {
    const steps = 10; 
    const intervalTime = duration / steps;

    const startVolume = audio.volume;
    const volStep = startVolume / steps;

    const fadeOutInterval = setInterval(() => {
        if (audio.volume > volStep) {
            audio.volume = Math.max(0, audio.volume - volStep);
        } else {
            audio.volume = 0;
            audio.pause();
            clearInterval(fadeOutInterval);
            if (callback) callback();
        }
    }, intervalTime);
  };

  useEffect(() => {
    if (audioRef.current) {
        if (isPaused) {
            audioRef.current.pause();
        } else if (slideshowActive) {
            audioRef.current.play().catch(e => console.error("Audio resume failed", e));
        }
    }
  }, [isPaused, slideshowActive]);

  useEffect(() => {
      let fadeOutTimeout: ReturnType<typeof setTimeout>;

      if (slideshowActive && slideshowConfig.audioFile) {
          const audioUrl = URL.createObjectURL(slideshowConfig.audioFile);
          const audio = new Audio(audioUrl);
          audio.loop = slideshowConfig.repeat;
          audio.volume = 0; 
          audioRef.current = audio;
          audio.play().catch(e => console.error("Audio playback failed", e));

          const fadeInterval = setInterval(() => {
              if (audio.volume < 0.9) {
                  audio.volume += 0.1;
              } else {
                  audio.volume = 1;
                  clearInterval(fadeInterval);
              }
          }, 200);

          if (!slideshowConfig.repeat) {
              const slideDurationMs = slideshowConfig.duration * 1000;
              const totalSlideshowDurationMs = likedRenderings.length * slideDurationMs;
              const fadeOutStartTime = Math.max(0, totalSlideshowDurationMs - slideDurationMs); 

              fadeOutTimeout = setTimeout(() => {
                  if (audioRef.current && !audioRef.current.paused && !audioRef.current.loop) {
                      fadeOutAudio(audioRef.current, slideDurationMs);
                  }
              }, fadeOutStartTime);
          }

          return () => {
              clearInterval(fadeInterval);
              clearTimeout(fadeOutTimeout);
              URL.revokeObjectURL(audioUrl);
          };
      }
  }, [slideshowActive, slideshowConfig.audioFile, slideshowConfig.repeat, slideshowConfig.duration, likedRenderings.length]);

  useEffect(() => {
      if (slideshowActive && !isPaused) {
          slideTimerRef.current = setInterval(() => {
              nextSlide();
          }, slideshowConfig.duration * 1000);
      }
      return () => {
          if (slideTimerRef.current) clearInterval(slideTimerRef.current);
      };
  }, [slideshowActive, isPaused, slideshowConfig.duration, likedRenderings.length, slideshowConfig.repeat]);


  const closeSlideshow = () => {
    if (audioRef.current && !audioRef.current.paused) {
        fadeOutAudio(audioRef.current, 1000, () => {
             audioRef.current = null;
        });
    } else {
        audioRef.current = null;
    }
    setSlideshowActive(false);
    setIsPaused(false);
  };

  const nextSlide = () => {
    setCurrentSlide((prev) => {
        const next = prev + 1;
        if (next >= likedRenderings.length) {
            if (slideshowConfig.repeat) {
                return 0; 
            } else {
                closeSlideshow(); 
                return prev;
            }
        }
        return next;
    });
  }

  const prevSlide = (e?: React.MouseEvent) => {
    if(e) e.stopPropagation();
    setCurrentSlide((prev) => (prev - 1 + likedRenderings.length) % likedRenderings.length);
  }

  const nextSlideManual = (e?: React.MouseEvent) => {
    if(e) e.stopPropagation();
    nextSlide();
  }

  const handleBulkDelete = () => {
    if(selectedRenderings.length > 0) {
      onDeleteRenderings(selectedRenderings);
      setSelectedRenderings([]);
    }
  }

  const handleBulkEmail = async () => {
    if (selectedRenderings.length === 0) return;

    const selectedList = renderings.filter(r => selectedRenderings.includes(r.id));
    const allLiked = selectedList.every(r => r.liked);

    if (!allLiked) {
      alert("Please 'Like' all selected renderings to enable email sharing.");
      return;
    }

    if (selectedList.length === 1) {
      // Use single sharing logic (trigger via ref or just re-implement)
      const r = selectedList[0];
      const fileName = `${r.category.replace(/\s+/g, '_')}_${r.id.substring(0, 6)}.jpg`;
      try {
        const response = await fetch(r.imageUrl);
        const blob = await response.blob();
        const file = new File([blob], fileName, { type: 'image/jpeg' });
        if (navigator.canShare && navigator.canShare({ files: [file] })) {
          await navigator.share({ files: [file], title: r.category });
        } else {
          // Manual mailto fallback
          const link = document.createElement('a');
          link.href = r.imageUrl;
          link.download = fileName;
          link.click();
          const subject = encodeURIComponent(`Architectural Rendering: ${r.category}`);
          const body = encodeURIComponent(`Attached is the ${r.category} rendering.\n\n(Attach ${fileName})`);
          window.location.href = `mailto:?subject=${subject}&body=${body}`;
        }
      } catch (e) { alert("Sharing failed."); }
      return;
    }

    // MULTIPLE ITEMS: Zip and email
    try {
      const zip = new JSZip();
      const folder = zip.folder("renderings");

      for (const r of selectedList) {
        const base64Data = r.imageUrl.split(',')[1];
        folder?.file(`${r.category.replace(/\s+/g, '_')}_${r.id.substring(0, 6)}.jpg`, base64Data, { base64: true });
      }

      const content = await zip.generateAsync({ type: "blob" });
      const zipName = `House_Renderings_${Date.now()}.zip`;

      // Download the zip
      const url = URL.createObjectURL(content);
      const link = document.createElement('a');
      link.href = url;
      link.download = zipName;
      link.click();
      URL.revokeObjectURL(url);

      // Open email
      const subject = encodeURIComponent(`Architectural Project: ${housePlan.title} Renderings`);
      const body = encodeURIComponent(`Hello,\n\nI've attached a zip file containing ${selectedList.length} renderings for the project: "${housePlan.title}".\n\n(Please attach the downloaded file: ${zipName})\n\nSent via Architect 3D.`);
      window.location.href = `mailto:?subject=${subject}&body=${body}`;

    } catch (err) {
      console.error("Zipping error:", err);
      alert("Failed to create zip file for email.");
    }
  };

  const handleGenerateVideoClick = () => {
    const prompt = `Create a cinematic 30-second video tour of the exterior of a ${housePlan.style} house, based on the description: "${initialPrompt}". Showcase both the front and back of the house using smooth camera movements and dramatic lighting, for example during a golden hour sunset. The video should pan smoothly around the property and include an inspiring background music track.`;
    onGenerateVideoTour(prompt);
  };

  const handleGenerateMarketingVideo = () => {
      if (!canCreateMarketingVideo) return;
      const totalDuration = (likedRenderings.length * 4) + 8;
      const shotList = likedRenderings.map((rendering, index) => {
        const detailsPart = rendering.prompt.split('incorporate the following specific details for this room: ')[1]?.split('.')[0] || `a beautiful ${rendering.category}`;
        return `
---
**Shot ${index + 2}: Scene of the ${rendering.category}**
- **Duration**: 4 seconds.
- **Description**: A photorealistic view of the ${rendering.category}. It must include these specific features: ${detailsPart}. The scene should have warm, natural lighting and a luxurious feel.
- **Camera Movement**: Use a slow, subtle camera movement (e.g., pan left, dolly in, gentle zoom).
---
`;
      }).join('');

      const prompt = `
You are a professional video director creating a high-end, cinematic real estate marketing video for "C&SH Group Properties, LLC".
**CRITICAL INSTRUCTIONS:**
1.  **Total Duration:** The final video MUST be exactly **${totalDuration} seconds** long.
2.  **Structure:** The video must follow the precise SHOT LIST provided below.
3.  **Pacing:** Each scene described in the shot list must be exactly 4 seconds long.
4.  **Music:** The video must have an inspiring, sophisticated, and instrumental background music track appropriate for a luxury property tour. The music must gently start to fade out 8 seconds before the end of the video.
5.  **Quality:** All scenes must be photorealistic, with high-end architectural visualization and cinematic lighting.
**--- SHOT LIST ---**
---
**Shot 1: Title Card**
- **Duration**: 4 seconds.
- **Content**: Display the text "${housePlan.title}" in an elegant, minimal font on a clean, professional background.
---
${shotList}
---
**Shot ${likedRenderings.length + 2}: Outro Card**
- **Duration**: 4 seconds.
- **Content**: Display the company name "C&SH Group Properties, LLC" and a contact number "(555) 123-4567". Match the style of the title card.
---
`;
      onGenerateVideoTour(prompt);
  };

  const handleEnlarge = (imageUrl: string) => {
    setEnlargedImageUrl(imageUrl);
  };

  const handleCloseEnlarged = () => {
    setEnlargedImageUrl(null);
  };

  const getSmartCaption = (rendering: Rendering) => {
      if (!rendering.prompt) return `A professional visualization of the ${rendering.category}.`;

      const detailsRegex = /incorporate the following (?:specific )?details.*?: (.*?)(?:\.|$| Crucially)/i;
      const detailsMatch = rendering.prompt.match(detailsRegex);

      if (detailsMatch && detailsMatch[1] && detailsMatch[1].trim().length > 5) {
          const details = detailsMatch[1].trim();
          return `${rendering.category} designed ${details}.`;
      }
      const conceptRegex = /(?:concept|description)(?: is|): "(.*?)"/i;
      const conceptMatch = rendering.prompt.match(conceptRegex);
      if (conceptMatch && conceptMatch[1]) {
           let concept = conceptMatch[1].trim();
           if (concept.length > 120) concept = concept.substring(0, 117) + '...';
           return `${rendering.category}: ${concept}`;
      }
      return `A stunning 3D visualization of the ${rendering.category}.`;
  };

  const getTransitionClass = () => {
      switch(slideshowConfig.transition) {
          case 'slide': return 'transition-transform duration-700 ease-in-out';
          case 'zoom': return 'transition-transform duration-1000 ease-in-out scale-105';
          case 'fade': default: return 'transition-opacity duration-1000 ease-in-out';
      }
  };

  // Reorder Logic
  const handleDragStart = (e: React.DragEvent, index: number) => {
    setDraggedRenderingIndex(index);
    e.dataTransfer.effectAllowed = "move";
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    e.dataTransfer.dropEffect = "move";
  };

  const handleDrop = (e: React.DragEvent, targetIndex: number) => {
    e.preventDefault();
    if (draggedRenderingIndex === null || draggedRenderingIndex === targetIndex) return;

    const newRenderings = [...renderings];
    const [movedItem] = newRenderings.splice(draggedRenderingIndex, 1);
    newRenderings.splice(targetIndex, 0, movedItem);

    onReorderRenderings(newRenderings);
    setDraggedRenderingIndex(null);
  };

  const selectedCategory = selectedRoom?.name;
  const canRecreate = selectedCategory && (selectedCategory === 'Front Exterior' || selectedCategory === 'Back Exterior');
  const hasRenderingForSelected = canRecreate ? renderings.some(r => r.category === selectedCategory) : false;

  return (
    <div>
      <div className="text-center mb-8 relative">
        <h2 className="text-3xl md:text-4xl font-bold text-gray-800 dark:text-white flex items-center justify-center gap-3">
            {housePlan.title}
            {isViewOnly && <Lock className="h-6 w-6 text-gray-400" title="View Only" />}
        </h2>
        <p className="text-lg text-brand-600 dark:text-brand-400 font-medium mt-1">{housePlan.style}</p>

        {isOwner && (
            <div className="absolute top-0 right-0">
                 <button 
                  onClick={onOpenShareModal}
                  className="flex items-center gap-2 px-4 py-2 text-sm font-medium text-brand-600 bg-white border border-brand-200 rounded-full hover:bg-brand-50 shadow-sm transition-colors"
                >
                    <Share2 className="h-4 w-4" /> Share
                </button>
            </div>
        )}
      </div>

      {error && (
        <div className="mb-6 flex items-center justify-between p-4 text-sm text-red-800 rounded-lg bg-red-50 dark:bg-gray-800 dark:text-red-400" role="alert">
            <div className="flex items-center">
                <AlertTriangle className="flex-shrink-0 inline w-5 h-5 mr-3" />
                <div>
                    <span className="font-medium">Error:</span> {error}
                </div>
            </div>
            <button onClick={onErrorClear} className="p-1.5 rounded-full hover:bg-red-100 dark:hover:bg-gray-700" aria-label="Dismiss error">
                <X className="h-4 w-4"/>
            </button>
        </div>
      )}

      {isViewOnly && (
         <div className="mb-6 p-3 bg-blue-50 dark:bg-blue-900/20 text-blue-700 dark:text-blue-300 rounded-lg text-center text-sm">
             You are viewing this project in <strong>Read-Only Mode</strong>. Editing and generation are disabled.
         </div>
      )}

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* Column 1: Room List */}
        <div className="lg:col-span-2 bg-white dark:bg-gray-800 p-4 rounded-lg shadow-md h-fit sticky top-24">
          <h3 className="font-bold text-lg mb-2">Exterior</h3>
          <ul className="mb-4">
            {exteriorRooms.map(room => (
              <li key={room.name}>
                <button
                  onClick={() => handleRoomSelect(room)}
                  className={`w-full text-left px-3 py-2 rounded-md text-sm font-medium transition-colors ${
                    selectedRoom?.name === room.name
                      ? 'bg-brand-100 text-brand-700 dark:bg-brand-900 dark:text-brand-200'
                      : 'hover:bg-gray-100 dark:hover:bg-gray-700'
                  }`}
                >
                  {room.name}
                </button>
              </li>
            ))}
          </ul>

          <h3 className="font-bold text-lg mb-2 flex items-center gap-2 pt-4 border-t border-gray-200 dark:border-gray-700"><LayoutGrid className="h-5 w-5 text-brand-500"/> Rooms</h3>
          <ul>
            {interiorRooms.map(room => (
              <li key={room.name}>
                <button
                  onClick={() => handleRoomSelect(room)}
                  className={`w-full text-left px-3 py-2 rounded-md text-sm font-medium transition-colors ${
                    selectedRoom?.name === room.name
                      ? 'bg-brand-100 text-brand-700 dark:bg-brand-900 dark:text-brand-200'
                      : 'hover:bg-gray-100 dark:hover:bg-gray-700'
                  }`}
                >
                  {room.name}
                </button>
              </li>
            ))}
          </ul>
          {!isViewOnly && (
            <div className="mt-4 pt-4 border-t border-gray-200 dark:border-gray-700">
                <button
                    onClick={() => setIsAddRoomModalOpen(true)}
                    className="w-full flex items-center justify-center gap-2 px-3 py-2 text-sm font-medium text-brand-600 dark:text-brand-400 hover:bg-brand-50 dark:hover:bg-gray-700 rounded-md transition-colors"
                >
                    <PlusCircle className="h-5 w-5" />
                    Add Room
                </button>
            </div>
          )}
        </div>

        {/* Column 2: Renderings */}
        <div className="lg:col-span-7">
          <div className='flex justify-between items-center mb-4'>
            <h3 className="font-bold text-xl">Renderings</h3>
            <div className="flex items-center gap-2 flex-wrap justify-end">
                {selectedRenderings.length > 0 && (
                   <button 
                      onClick={handleBulkEmail}
                      className="flex items-center gap-2 px-3 py-1.5 text-sm font-medium text-white bg-indigo-500 rounded-md hover:bg-indigo-600 transition-colors"
                      title="Share selected as email"
                    >
                        <Send className="h-4 w-4" /> Email ({selectedRenderings.length})
                    </button>
                )}
                {renderings.length > 1 && !isViewOnly && (
                    <button 
                        onClick={() => setIsReordering(!isReordering)}
                        className={`flex items-center gap-2 px-3 py-1.5 text-sm font-medium rounded-md transition-colors ${
                            isReordering 
                                ? 'bg-orange-500 hover:bg-orange-600 text-white shadow-inner' 
                                : 'bg-gray-200 dark:bg-gray-700 text-gray-700 dark:text-gray-300 hover:bg-gray-300 dark:hover:bg-gray-600'
                        }`}
                        title="Drag and drop images to change order"
                    >
                        <Move className="h-4 w-4" /> {isReordering ? 'Done' : 'Rearrange'}
                    </button>
                )}
                {canRecreate && hasRenderingForSelected && !isViewOnly && (
                  <button 
                    onClick={() => selectedCategory && onRecreateRendering(selectedCategory)} 
                    disabled={isLoading || !isKeyReady}
                    className="flex items-center gap-2 px-3 py-1.5 text-sm font-medium text-white bg-blue-500 rounded-md hover:bg-blue-600 transition-colors disabled:bg-gray-400 disabled:cursor-not-allowed"
                  >
                      <RefreshCw className="h-4 w-4" /> Re-Create {selectedCategory}
                  </button>
                )}
                 <button 
                  onClick={handleGenerateMarketingVideo}
                  disabled={!canCreateMarketingVideo || isLoading || !isKeyReady}
                  title={!canCreateMarketingVideo ? "Like 10+ renderings to create a marketing video." : "Create a Marketing Video"}
                  className="flex items-center gap-2 px-3 py-1.5 text-sm font-medium text-white bg-teal-500 rounded-md hover:bg-teal-600 transition-colors disabled:bg-gray-400 disabled:cursor-not-allowed"
                >
                    <Film className="h-4 w-4" /> Marketing Video
                </button>
                <button 
                  onClick={handleGenerateVideoClick} 
                  disabled={isLoading || !isKeyReady}
                  className="flex items-center gap-2 px-3 py-1.5 text-sm font-medium text-white bg-purple-500 rounded-md hover:bg-purple-600 transition-colors disabled:bg-gray-400 disabled:cursor-not-allowed"
                >
                    <Video className="h-4 w-4" /> Video Tour
                </button>
                {canStartSlideshow && (
                    <button 
                      onClick={handleSlideshowClick} 
                      disabled={isLoading}
                      className="flex items-center gap-2 px-3 py-1.5 text-sm font-medium text-white bg-green-500 rounded-md hover:bg-green-600 transition-colors disabled:bg-gray-400 disabled:cursor-not-allowed"
                    >
                        <Play className="h-4 w-4" /> Slideshow
                    </button>
                )}
                {selectedRenderings.length > 0 && !isViewOnly && (
                    <button 
                      onClick={handleBulkDelete} 
                      disabled={isLoading}
                      className="flex items-center gap-2 px-3 py-1.5 text-sm font-medium text-white bg-red-500 rounded-md hover:bg-red-600 transition-colors disabled:bg-gray-400 disabled:cursor-not-allowed"
                    >
                        <Trash2 className="h-4 w-4" /> Delete ({selectedRenderings.length})
                    </button>
                )}
            </div>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            {renderings.map((rendering, index) => (
              <div
                key={rendering.id}
                draggable={isReordering}
                onDragStart={(e) => handleDragStart(e, index)}
                onDragOver={handleDragOver}
                onDrop={(e) => handleDrop(e, index)}
                className={`relative rounded-lg transition-transform ${isReordering ? 'cursor-grab active:cursor-grabbing hover:scale-[1.02]' : ''} ${draggedRenderingIndex === index ? 'opacity-50' : ''}`}
              >
                  {isReordering && (
                      <div className="absolute inset-0 z-20 flex items-center justify-center bg-black/40 rounded-lg border-2 border-dashed border-white/50 pointer-events-none">
                          <Move className="h-12 w-12 text-white/80" />
                      </div>
                  )}
                  <ImageCard
                    rendering={rendering}
                    onUpdate={onUpdateRendering}
                    isSelected={selectedRenderings.includes(rendering.id)}
                    onSelectToggle={handleSelectToggle}
                    onEnlarge={handleEnlarge}
                  />
              </div>
            ))}
          </div>
        </div>

        {/* Column 3: Customization Panel */}
        <div className="lg:col-span-3">
            <div className="sticky top-24">
              {selectedRoom ? (
