            >
              <X className="h-6 w-6"/>
            </button>
          </div>
        </div>
      )}

      <AddRoomModal
        isOpen={isAddRoomModalOpen}
        onClose={() => setIsAddRoomModalOpen(false)}
        onAddRoom={(newRoom) => {
            onAddRoom(newRoom);
            setIsAddRoomModalOpen(false);
        }}
        existingRoomNames={housePlan.rooms.map(r => r.name)}
      />
    </div>
  );
};

