import React, { useState } from 'react';
import { Rendering } from '../types';
import { Heart, Star, Download, Send, CheckSquare, Square, ZoomIn, Pencil, X, Wand2 } from 'lucide-react';

interface ImageCardProps {
  rendering: Rendering;
  onRefine?: (id: string, instructions: string) => void;
  onUpdate: (id: string, updates: Partial<Rendering>) => void;
  isSelected: boolean;
  onSelectToggle: (id: string) => void;
  onEnlarge: (imageUrl: string) => void;
}

const ImageCard: React.FC<ImageCardProps> = ({ rendering, onRefine, onUpdate, isSelected, onSelectToggle, onEnlarge }) => {
  const { id, category, imageUrl, liked, favorited } = rendering;
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);
  const [editInstructions, setEditInstructions] = useState('');

  const handleLike = () => onUpdate(id, { liked: !liked });
  const handleFavorite = () => onUpdate(id, { favorited: !favorited });

  const handleDownload = () => {
    if (!liked) {
      alert("Please 'Like' the rendering to enable download.");
      return;
    }
    const link = document.createElement('a');
    link.href = imageUrl;
    link.download = `${category.replace(/\s+/g, '_')}_${id.substring(0, 6)}.jpg`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  }

  const handleEmail = async () => {
    if (!liked) {
      alert("Please 'Like' the rendering to enable email sharing.");
      return;
    }

    const fileName = `${category.replace(/\s+/g, '_')}_${id.substring(0, 6)}.jpg`;

    try {
      const response = await fetch(imageUrl);
      const blob = await response.blob();
      const file = new File([blob], fileName, { type: 'image/jpeg' });

      if (navigator.canShare && navigator.canShare({ files: [file] })) {
        await navigator.share({
          files: [file],
          title: `Architectural Rendering: ${category}`,
          text: `Check out this ${category} rendering I created with Architect 3D!`,
        });
      } else {
        handleDownload();
        const subject = encodeURIComponent(`Architectural Rendering: ${category}`);
        const body = encodeURIComponent(`Hello,\n\nI've attached the architectural rendering for the ${category}.\n\n(Note: If the file didn't attach automatically, please attach the recently downloaded file: ${fileName})\n\nSent via Architect 3D Home Modeler.`);
        window.location.href = `mailto:?subject=${subject}&body=${body}`;
      }
    } catch (err) {
      console.error("Error sharing rendering:", err);
      alert("Failed to share image. Please try downloading it manually.");
    }
  }

  const handleRefineSubmit = () => {
    if (onRefine && editInstructions.trim()) {
        onRefine(id, editInstructions.trim());
        setIsEditModalOpen(false);
        setEditInstructions('');
    }
  };

  const canEdit = category === 'Front Exterior';

  return (
    <div className={`group relative bg-white dark:bg-gray-800 rounded-lg shadow-md overflow-hidden border-2 ${isSelected ? 'border-brand-500' : 'border-transparent'}`}>
      <img src={imageUrl} alt={`Rendering of ${category}`} className="w-full h-64 object-cover" />

      <div
        role="button"
        tabIndex={0}
        onClick={() => onEnlarge(imageUrl)}
        onKeyDown={(e) => e.key === 'Enter' && onEnlarge(imageUrl)}
        className="absolute top-0 left-0 w-full h-64 bg-black bg-opacity-0 group-hover:bg-opacity-50 flex items-center justify-center cursor-pointer transition-all duration-300"
        aria-label={`Enlarge rendering of ${category}`}
      >
        <ZoomIn className="h-12 w-12 text-white opacity-0 group-hover:opacity-100 transition-opacity duration-300" />
      </div>

      <div className="absolute top-2 right-2 z-10 flex flex-col gap-2">
         <button onClick={() => onSelectToggle(id)} className="p-2 bg-black bg-opacity-50 text-white rounded-full hover:bg-opacity-75 transition-opacity">
            {isSelected ? <CheckSquare className="h-5 w-5 text-brand-400"/> : <Square className="h-5 w-5"/>}
        </button>
      </div>

      <div className="p-4">
        <div className="flex justify-between items-start">
            <h4 className="font-bold text-lg">{category}</h4>
            {canEdit && (
                <button 
                    onClick={() => setIsEditModalOpen(true)}
                    className="flex items-center gap-1 text-xs font-medium text-brand-600 dark:text-brand-400 hover:bg-brand-50 dark:hover:bg-brand-900/30 px-2 py-1 rounded transition-colors"
                >
                    <Pencil className="h-3 w-3" /> Edit Rendering
                </button>
            )}
        </div>

        <div className="mt-3 flex items-center justify-between">
          <div className="flex items-center space-x-2">
            <button onClick={handleLike} className={`p-2 rounded-full hover:bg-red-100 dark:hover:bg-red-900/50 transition-colors ${liked ? 'text-red-500' : 'text-gray-400'}`}>
              <Heart className="h-5 w-5" />
            </button>
            <button onClick={handleFavorite} className={`p-2 rounded-full hover:bg-yellow-100 dark:hover:bg-yellow-900/50 transition-colors ${favorited ? 'text-yellow-400' : 'text-gray-400'}`}>
              <Star className="h-5 w-5" />
            </button>
          </div>
          <div className="flex items-center space-x-2">
             <button onClick={handleDownload} disabled={!liked} className="p-2 rounded-full text-gray-400 hover:bg-gray-200 dark:hover:bg-gray-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors" title="Download Image">
                <Download className="h-5 w-5" />
            </button>
            <button onClick={handleEmail} disabled={!liked} className="p-2 rounded-full text-gray-400 hover:bg-gray-200 dark:hover:bg-gray-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors" title="Email Image">
                <Send className="h-5 w-5" />
            </button>
          </div>
        </div>
      </div>

      {/* Refine Modal */}
      {isEditModalOpen && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
            <div className="bg-white dark:bg-gray-800 rounded-xl shadow-2xl w-full max-w-md overflow-hidden">
                <div className="p-6 border-b dark:border-gray-700 flex justify-between items-center">
                    <h3 className="font-bold text-lg flex items-center gap-2">
                        <Pencil className="h-5 w-5 text-brand-600" />
                        Edit Front Exterior
                    </h3>
                    <button onClick={() => setIsEditModalOpen(false)} className="text-gray-400 hover:text-gray-600">
                        <X className="h-5 w-5" />
                    </button>
                </div>
                <div className="p-6">
                    <p className="text-sm text-gray-600 dark:text-gray-400 mb-4">
                        Describe what you'd like to add, remove, or change in this specific rendering. 
                        Gemini will modify the existing image based on your instructions.
                    </p>
                    <textarea 
                        value={editInstructions}
                        onChange={(e) => setEditInstructions(e.target.value)}
                        placeholder="e.g., Change the front door to a dark mahogany wood, and add more vibrant purple flowers to the garden beds..."
                        className="w-full h-32 p-3 border dark:border-gray-600 rounded-lg bg-gray-50 dark:bg-gray-700 text-sm focus:ring-2 focus:ring-brand-500 outline-none"
                    />
                    <div className="mt-6 flex gap-3">
                        <button 
                            onClick={() => setIsEditModalOpen(false)}
                            className="flex-1 px-4 py-2 border dark:border-gray-600 rounded-lg text-sm font-medium hover:bg-gray-50 dark:hover:bg-gray-700 transition-colors"
                        >
                            Cancel
                        </button>
                        <button 
                            onClick={handleRefineSubmit}
                            disabled={!editInstructions.trim()}
                            className="flex-1 px-4 py-2 bg-brand-600 hover:bg-brand-700 disabled:bg-gray-400 text-white rounded-lg text-sm font-bold flex items-center justify-center gap-2 transition-colors"
                        >
                            <Wand2 className="h-4 w-4" />
                            Refine Image
                        </button>
                    </div>
                </div>
            </div>
        </div>
      )}
    </div>
  );
};

export default ImageCard;

import React, { useState, useEffect } from 'react';

const Footer: React.FC = () => {
  const [lastUpdated, setLastUpdated] = useState<string>('');
  const currentYear = new Date().getFullYear();

  useEffect(() => {
    // Generate timestamp in YYYYMMDDHHMISS format
    const now = new Date();
    const year = now.getFullYear();
    const month = String(now.getMonth() + 1).padStart(2, '0');
    const day = String(now.getDate()).padStart(2, '0');
    const hours = String(now.getHours()).padStart(2, '0');
    const minutes = String(now.getMinutes()).padStart(2, '0');
    const seconds = String(now.getSeconds()).padStart(2, '0');

    setLastUpdated(`${year}${month}${day}${hours}${minutes}${seconds}`);
  }, []);

  return (
    <footer className="w-full bg-white dark:bg-gray-900 border-t border-gray-200 dark:border-gray-800 py-6 mt-auto z-10 relative">
        <div className="container mx-auto px-4 text-center">
            <p className="text-sm font-bold text-gray-900 dark:text-white uppercase tracking-wider mb-2">
                A C.&.S.H. Group Properties A.I. APP
            </p>
            <div className="flex flex-col sm:flex-row justify-center items-center gap-y-1 gap-x-4 text-xs text-gray-500 dark:text-gray-400">
                <span>&copy; {currentYear} C.&.S.H. Group Properties</span>
                <span className="hidden sm:inline text-gray-300 dark:text-gray-700">|</span>
                <span className="font-mono">Last Updated: {lastUpdated}</span>
            </div>
        </div>
    </footer>
  );
};

export default Footer;

import React, { useState, useCallback, useEffect, useMemo, useRef } from 'react';
import { AppView, HousePlan, Rendering, SavedDesign, Room, User, AccessLevel } from './types';
import HomePage from './components/HomePage';
import ResultsPage from './components/ResultsPage';
import Header from './components/Header';
import LandingPage from './components/LandingPage';
import { generateHousePlanFromDescription, generateImage, generateVideo, generateImageFromImage } from './services/geminiService';
import { authService } from './services/authService';
import { dbService } from './services/dbService';
import { cloudService } from './services/cloudService';
import LoadingOverlay from './components/LoadingOverlay';
import ApiKeyPrompt from './components/ApiKeyPrompt';
import ShareModal from './components/ShareModal';
import Footer from './components/Footer';

interface UploadedFiles {
    frontPlan: File | null;
    backPlan: File | null;
    facadeImage: File | null;
}

function App() {
  const [view, setView] = useState<AppView>(AppView.Home);
  const [isLoading, setIsLoading] = useState(false);
  const [isAuthLoading, setIsAuthLoading] = useState(true);
  const [isSavingCloud, setIsSavingCloud] = useState(false);
  const [loadingMessage, setLoadingMessage] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [videoUrl, setVideoUrl] = useState<string | null>(null);

  const [savedDesigns, setSavedDesigns] = useState<SavedDesign[]>([]);
  const [currentDesignId, setCurrentDesignId] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [isKeyReady, setIsKeyReady] = useState<boolean | null>(null);
  const [isShareModalOpen, setIsShareModalOpen] = useState(false);

  const [user, setUser] = useState<User | null>(null);
  const userRef = useRef<User | null>(null);

  const getUserId = useCallback(() => {
    return user ? user.email : 'anonymous';
  }, [user]);

  const totalRenderingsCount = useMemo(() => {
    return savedDesigns.filter(d => d.accessLevel === 'owner').reduce((acc, design) => acc + design.renderings.length, 0);
  }, [savedDesigns]);

  useEffect(() => {
    const unsubscribe = authService.onAuthStateChanged((newUser) => {
      const prevEmail = userRef.current?.email;
      const newEmail = newUser?.email;

      if (prevEmail !== newEmail) {
          setUser(newUser);
      }
      setIsAuthLoading(false);
    });
    return () => unsubscribe();
  }, []);

  useEffect(() => {
      const handleDataLoadAndMigration = async () => {
        const currentUser = user;
        const previousUser = userRef.current;
        const currentUserId = currentUser ? currentUser.email : 'anonymous';

        userRef.current = currentUser;

        if (!currentUser) {
            setSavedDesigns([]);
            return;
        }

        if (currentUser && !previousUser) {
             try {
                const anonymousDesigns = await dbService.getUserDesigns('anonymous');
                if (anonymousDesigns.length > 0) {
                    setTimeout(async () => {
                         if (window.confirm(`Welcome ${currentUser.name}! You have designs saved as a guest. Would you like to move them to your account?`)) {
                            await dbService.reassignDesigns('anonymous', currentUser.email);
                            try {
                                const designs = await dbService.getUserDesigns(currentUser.email);
                                for (const design of designs) {
                                    await cloudService.saveDesign(currentUser.email, design);
                                }
                            } catch (err) {
                                console.warn("Background cloud sync failed during migration", err);
                            }
                            const designs = await dbService.getUserDesigns(currentUser.email);
                            setSavedDesigns(designs);
                        }
                    }, 500);
                }
             } catch (e) {
                 console.error("Error checking for anonymous designs:", e);
             }
        }

        try {
            let allDesigns = await dbService.getUserDesigns(currentUserId);
            allDesigns = allDesigns.map(d => ({ ...d, ownerId: currentUserId, accessLevel: 'owner' }));

            if (currentUser && currentUser.email !== 'anonymous') {
                try {
                    const cloudOwned = await cloudService.getUserDesigns(currentUserId);
                    const cloudShared = await cloudService.getSharedDesigns(currentUser.email);

                    for (const d of cloudOwned) {
                        await dbService.saveDesign(d, currentUserId);
                    }

                    const refreshedLocal = await dbService.getUserDesigns(currentUserId);
                    const finalOwned = refreshedLocal.map(d => ({ ...d, ownerId: currentUserId, accessLevel: 'owner' as AccessLevel }));
                    allDesigns = [...finalOwned, ...cloudShared];
                } catch (cloudErr) {
                    console.error("Cloud fetch failed, using local", cloudErr);
                }
            }
            setSavedDesigns(allDesigns);
        } catch (e) {
            console.error("Failed to load designs:", e);
            setError("Could not load saved designs.");
        }
      };

      if (!isAuthLoading) {
          handleDataLoadAndMigration();
      }
  }, [user, isAuthLoading]);

  const checkApiKey = useCallback(async () => {
    if (window.aistudio && typeof window.aistudio.hasSelectedApiKey === 'function') {
      try {
        const hasKey = await window.aistudio.hasSelectedApiKey();
        setIsKeyReady(hasKey);
      } catch (e) {
        console.error("Error checking for API key:", e);
        setIsKeyReady(false);
      }
    } else {
      setIsKeyReady(true);
    }
  }, []);

  useEffect(() => {
    checkApiKey();
  }, [checkApiKey]);

  const currentDesign = useMemo(() => {
    return savedDesigns.find(d => d.housePlan.id === currentDesignId) || null;
  }, [currentDesignId, savedDesigns]);

  const filteredDesigns = useMemo(() => {
    const sorted = [...savedDesigns].sort((a, b) => b.housePlan.createdAt - a.housePlan.createdAt);
    if (!searchQuery) return sorted;

    return sorted.filter(design => {
      const query = searchQuery.toLowerCase();
      const { title, style, rooms } = design.housePlan;
      return (
        title.toLowerCase().includes(query) ||
        style.toLowerCase().includes(query) ||
        rooms.some(room => room.name.toLowerCase().includes(query)) ||
        design.initialPrompt.toLowerCase().includes(query)
      );
    });
  }, [searchQuery, savedDesigns]);

  const saveDesignChange = useCallback(async (updatedDesign: SavedDesign) => {
      const currentUserId = getUserId();
      const designOwnerId = updatedDesign.ownerId || currentUserId;
      const isOwner = designOwnerId === currentUserId;

      try {
          setSavedDesigns(prev => {
              const idx = prev.findIndex(d => d.housePlan.id === updatedDesign.housePlan.id);
              if (idx >= 0) {
                  const newArr = [...prev];
                  newArr[idx] = updatedDesign;
                  return newArr;
              } else {
                  return [...prev, updatedDesign];
              }
          });

          if (isOwner) {
            await dbService.saveDesign(updatedDesign, currentUserId);
          }

          if (user && user.email !== 'anonymous') {
             await cloudService.saveDesign(designOwnerId, updatedDesign);
          }
      } catch (err) {
          console.error("Failed to save design:", err);
          setError("Failed to save changes.");
      }
  }, [getUserId, user]);

  const handleManualSaveToCloud = useCallback(async () => {
      if (!currentDesign) return;
      if (!user) {
          alert("You must be logged in to save to the cloud.");
          return;
      }

      setIsSavingCloud(true);
      try {
          const ownerId = currentDesign.ownerId || user.email;
          await cloudService.saveDesign(ownerId, currentDesign);
          if (ownerId === user.email) {
             await dbService.saveDesign(currentDesign, user.email);
          }
          alert("Design successfully saved!");
      } catch (err) {
          console.error(err);
          setError("Failed to save. Please try again.");
      } finally {
          setIsSavingCloud(false);
      }
  }, [currentDesign, user]);

  const handleError = useCallback((err: unknown, defaultView: AppView = AppView.Home) => {
    const errorMessage = err instanceof Error ? err.message : 'An unknown error occurred.';
    if (errorMessage.includes('billing-enabled API key') || errorMessage.includes('select a valid key') || errorMessage.includes('Requested entity was not found')) {
        setIsKeyReady(false);
    }
    setError(errorMessage);
    if (defaultView === AppView.Home) {
        setView(AppView.Home);
    }
  }, []);

  const resetApp = useCallback(() => {
    setView(AppView.Home);
    setCurrentDesignId(null);
    setError(null);
    setIsLoading(false);
    setSearchQuery('');
    setVideoUrl(prev => {
        if(prev) URL.revokeObjectURL(prev);
        return null;
    });
  }, []);

  const handleSignOut = useCallback(async () => {
    await authService.signOut();
    resetApp();
  }, [resetApp]);

  const checkGuestLimit = useCallback(() => {
     if (user?.name === 'Guest Architect' && totalRenderingsCount >= 2) {
         if (window.confirm("Guest Account Limit Reached\n\nYou are limited to 2 active renderings as a Guest.\n\nPlease Sign In with your Google Account to create unlimited designs, access cloud storage, and advanced features.")) {
             handleSignOut();
         }
         return false;
     }
     return true;
  }, [user, totalRenderingsCount, handleSignOut]);

  const handleGenerationRequest = useCallback(async (description: string, files: UploadedFiles) => {
    if (!checkGuestLimit()) return;

    setIsLoading(true);
    setError(null);
    setLoadingMessage('Processing your design inputs...');

    try {
      const imageInputs: { file: File, description: string }[] = [];
      if (files.frontPlan) imageInputs.push({ file: files.frontPlan, description: "front architectural plan" });
      if (files.backPlan) imageInputs.push({ file: files.backPlan, description: "back architectural plan" });
      if (files.facadeImage) imageInputs.push({ file: files.facadeImage, description: "example facade for style reference" });

      const processedImages = await Promise.all(imageInputs.map(async (input) => {
          const reader = new FileReader();
          const base64 = await new Promise<string>((resolve, reject) => {
              reader.onload = () => resolve((reader.result as string).split(',')[1]);
              reader.onerror = reject;
              reader.readAsDataURL(input.file);
          });
          return { base64, mimeType: input.file.type, description: input.description };
      }));

      setLoadingMessage('Designing your dream home structure...');
      const planData = await generateHousePlanFromDescription(description, processedImages);

      const newHousePlan: HousePlan = {
          ...planData,
          id: crypto.randomUUID(),
          createdAt: Date.now(),
      };

      let frontImageUrl: string;
      let frontExteriorPrompt: string;
      const facadeForRendering = processedImages.find(p => p.description.includes('facade'));

      if (facadeForRendering) {
        setLoadingMessage('Rendering 3D model from your image...');
        frontExteriorPrompt = `Using the provided example facade image as a strong style reference, create a photorealistic, high-quality 3D architectural rendering of a complete house exterior. The overall design concept is: "${description}". Enhance the lighting, textures, and surroundings to create a professional visualization.`;
        frontImageUrl = await generateImageFromImage(frontExteriorPrompt, facadeForRendering.base64, facadeForRendering.mimeType);
      } else {
        setLoadingMessage('Rendering front exterior...');
        frontExteriorPrompt = `Photorealistic 3D rendering of the front exterior of a ${newHousePlan.style} house. This image should focus on the street-facing view, including the main entrance, facade, and any front yard landscaping. The overall architectural concept is: "${description}". Crucially, DO NOT include backyard-specific features like swimming pools, large patios, or putting greens in this front view.`;
        frontImageUrl = await generateImage(frontExteriorPrompt);
      }

      const frontRendering: Rendering = {
        id: crypto.randomUUID(),
        category: 'Front Exterior',
        imageUrl: frontImageUrl,
        prompt: frontExteriorPrompt,
        liked: false,
        favorited: false
      };

      const newDesign: SavedDesign = {
        housePlan: newHousePlan,
        renderings: [frontRendering],
        initialPrompt: description,
        uploadedImages: {
            frontPlan: processedImages.find(p => p.description.includes('front architectural plan')),
            backPlan: processedImages.find(p => p.description.includes('back architectural plan')),
            facadeImage: processedImages.find(p => p.description.includes('facade'))
        },
        ownerId: getUserId(),
        accessLevel: 'owner'
      };

      await saveDesignChange(newDesign);
      setCurrentDesignId(newHousePlan.id);
      setView(AppView.Results);

    } catch (err) {
      handleError(err, AppView.Home);
    } finally {
      setIsLoading(false);
      setLoadingMessage('');
    }
  }, [saveDesignChange, handleError, getUserId, checkGuestLimit]);

  const handleNewRendering = useCallback(async (prompt: string, category: string) => {
    if (!currentDesignId) return;
    if (!checkGuestLimit()) return;

    setIsLoading(true);
    setLoadingMessage(`Rendering ${category}...`);
    setError(null);
    try {
      const design = savedDesigns.find(d => d.housePlan.id === currentDesignId);
      if (!design) return;

      let imageUrl: string;
      const backPlanImage = design?.uploadedImages?.backPlan;

      if (category === 'Back Exterior' && backPlanImage) {
        imageUrl = await generateImageFromImage(prompt, backPlanImage.base64, backPlanImage.mimeType);
      } else {
        imageUrl = await generateImage(prompt);
      }

      const newRendering: Rendering = {
        id: crypto.randomUUID(),
        category,
        imageUrl,
        prompt,
        liked: false,
        favorited: false
      };

      const updatedDesign = { ...design, renderings: [...design.renderings, newRendering] };
      await saveDesignChange(updatedDesign);

    } catch (err) {
      handleError(err);
    } finally {
      setIsLoading(false);
      setLoadingMessage('');
    }
  }, [currentDesignId, savedDesigns, saveDesignChange, handleError, checkGuestLimit]);

  const handleRefineRendering = useCallback(async (renderingId: string, instructions: string) => {
    if (!currentDesignId) return;
    const design = savedDesigns.find(d => d.housePlan.id === currentDesignId);
    if (!design) return;

    if (design.accessLevel === 'view') {
        alert("You have 'View Only' access to this project.");
        return;
    }

    const rendering = design.renderings.find(r => r.id === renderingId);
    if (!rendering) return;

    setIsLoading(true);
    setLoadingMessage(`Refining ${rendering.category}...`);
    setError(null);

    try {
        const base64Data = rendering.imageUrl.split(',')[1];
        const mimeType = rendering.imageUrl.split(';')[0].split(':')[1];

        const refinePrompt = `You are a professional architectural visualizer. Modify the provided image according to these specific instructions: "${instructions}". Keep the overall structure and style consistent with the original image, but precisely apply the requested changes (adding or removing elements as described). Ensure the output is a high-quality photorealistic architectural rendering.`;

        const refinedImageUrl = await generateImageFromImage(refinePrompt, base64Data, mimeType);

        const updatedRendering: Rendering = {
            ...rendering,
            imageUrl: refinedImageUrl,
            prompt: `${rendering.prompt} | Refined with: ${instructions}`
        };

        const newRenderings = design.renderings.map(r => r.id === renderingId ? updatedRendering : r);
        const updatedDesign = { ...design, renderings: newRenderings };
        await saveDesignChange(updatedDesign);

    } catch (err) {
        handleError(err);
    } finally {
        setIsLoading(false);
        setLoadingMessage('');
    }
  }, [currentDesignId, savedDesigns, saveDesignChange, handleError]);

  const handleRecreateRendering = useCallback(async (category: string) => {
    if (!currentDesignId) return;
    const design = savedDesigns.find(d => d.housePlan.id === currentDesignId);
    if (!design) return;

    if (design.accessLevel === 'view') {
        alert("You have 'View Only' access to this project.");
        return;
    }

    const existingRendering = design.renderings.find(r => r.category === category);
    if (!existingRendering || (category !== 'Front Exterior' && category !== 'Back Exterior')) return;

    setIsLoading(true);
    setLoadingMessage(`Re-creating ${category}...`);
    setError(null);

    try {
      const { prompt } = existingRendering;
      let imageUrl: string;

      if (category === 'Front Exterior') {
         const facadeImage = design.uploadedImages?.facadeImage;
         if (facadeImage && prompt.includes("example facade")) {
            imageUrl = await generateImageFromImage(prompt, facadeImage.base64, facadeImage.mimeType);
         } else {
            imageUrl = await generateImage(prompt);
         }
      } else {
         const backPlan = design.uploadedImages?.backPlan;
         if (backPlan) {
            imageUrl = await generateImageFromImage(prompt, backPlan.base64, backPlan.mimeType);
         } else {
            imageUrl = await generateImage(prompt);
         }
      }

      const updatedRendering: Rendering = {
          ...existingRendering,
          imageUrl,
      };

      const newRenderings = design.renderings.map(r => r.id === existingRendering.id ? updatedRendering : r);
      const updatedDesign = { ...design, renderings: newRenderings };
      await saveDesignChange(updatedDesign);

    } catch (err) {
      handleError(err);
    } finally {
      setIsLoading(false);
      setLoadingMessage('');
    }
  }, [currentDesignId, savedDesigns, saveDesignChange, handleError]);

  const handleGenerateVideoTour = useCallback(async (prompt: string) => {
      setIsLoading(true);
      setLoadingMessage('Creating cinematic tour... This may take minutes.');
      setError(null);
      try {
          const url = await generateVideo(prompt);
          setVideoUrl(url);
      } catch (err) {
        handleError(err);
      } finally {
          setIsLoading(false);
          setLoadingMessage('');
      }
  }, [handleError]);

  const handleCloseVideo = useCallback(() => {
    if (videoUrl) {
      URL.revokeObjectURL(videoUrl);
    }
    setVideoUrl(null);
  }, [videoUrl]);

  const updateRendering = useCallback(async (renderingId: string, updates: Partial<Rendering>) => {
    if (!currentDesignId) return;
    const design = savedDesigns.find(d => d.housePlan.id === currentDesignId);
    if (!design) return;

    const newRenderings = design.renderings.map(r => r.id === renderingId ? { ...r, ...updates } : r);
    const updatedDesign = { ...design, renderings: newRenderings };
    await saveDesignChange(updatedDesign);
  }, [currentDesignId, savedDesigns, saveDesignChange]);

  const deleteRenderings = useCallback(async (renderingIds: string[]) => {
    if (!currentDesignId) return;
    const design = savedDesigns.find(d => d.housePlan.id === currentDesignId);
    if (!design) return;

    if (design.accessLevel === 'view') return;

    const newRenderings = design.renderings.filter(r => !renderingIds.includes(r.id));
    const updatedDesign = { ...design, renderings: newRenderings };
    await saveDesignChange(updatedDesign);
  }, [currentDesignId, savedDesigns, saveDesignChange]);

  const handleReorderRenderings = useCallback(async (reorderedRenderings: Rendering[]) => {
    if (!currentDesignId) return;
    const design = savedDesigns.find(d => d.housePlan.id === currentDesignId);
    if (!design) return;

    if (design.accessLevel === 'view') return;

    const updatedDesign = { ...design, renderings: reorderedRenderings };
    await saveDesignChange(updatedDesign);
  }, [currentDesignId, savedDesigns, saveDesignChange]);

  const handleSelectDesign = useCallback((designId: string) => {
    setCurrentDesignId(designId);
    setView(AppView.Results);
    setError(null);
  }, []);

  const handleDeleteDesign = useCallback(async (designId: string) => {
    const design = savedDesigns.find(d => d.housePlan.id === designId);
    if (!design) return;

    const isOwner = design.accessLevel === 'owner';
    const message = isOwner 
        ? "Are you sure you want to delete this design and all its renderings? This action cannot be undone."
        : "Remove this shared design from your list?";

    if (window.confirm(message)) {
      try {
        const userId = getUserId();

        if (isOwner) {
            await dbService.deleteDesign(designId);
            if (user && user.email !== 'anonymous') {
                await cloudService.deleteDesign(userId, designId);
            }
        } else {
            if (user) {
                await cloudService.removeShare(user.email, designId);
            }
        }

        setSavedDesigns(prev => prev.filter(d => d.housePlan.id !== designId));
        if (currentDesignId === designId) {
            resetApp();
        }
      } catch (err) {
        console.error("Failed to delete design", err);
        setError("Failed to delete design.");
      }
    }
  }, [currentDesignId, resetApp, getUserId, user, savedDesigns]);

  const handleAddRoom = useCallback(async (newRoom: Room) => {
    if (!currentDesignId) return;
    const design = savedDesigns.find(d => d.housePlan.id === currentDesignId);
    if (!design) return;

    if (design.accessLevel === 'view') return;

    const updatedHousePlan = {
        ...design.housePlan,
        rooms: [...design.housePlan.rooms, newRoom]
    };
    const updatedDesign = { ...design, housePlan: updatedHousePlan };
    await saveDesignChange(updatedDesign);
  }, [currentDesignId, savedDesigns, saveDesignChange]);

  const handleSelectKey = useCallback(async () => {
      if (window.aistudio && typeof window.aistudio.openSelectKey === 'function') {
        try {
          await window.aistudio.openSelectKey();
          setIsKeyReady(true);
          checkApiKey();
        } catch (e) {
          setError("Could not open API key selection. Please try again.");
        }
      } else {
          setIsKeyReady(true);
      }
  }, [checkApiKey]);

  const handleClearError = useCallback(() => setError(null), []);

  const handleSignIn = useCallback(async () => {
      setIsLoading(true);
      setLoadingMessage("Signing in with Google...");
      try {
        await authService.signIn();
      } catch (e) {
        setError("Sign in failed. Please try again.");
      } finally {
        setIsLoading(false);
        setLoadingMessage('');
      }
  }, []);

  const handleSignInGuest = useCallback(async () => {
      setIsLoading(true);
      setLoadingMessage("Setting up Guest Account...");
      try {
        await authService.signInGuest();
      } catch (e) {
        console.error("Guest Sign In Error:", e);
        setError("Guest sign in failed. Please try again.");
      } finally {
        setIsLoading(false);
        setLoadingMessage('');
      }
  }, []);

  const handleShareDesign = useCallback(async (email: string, permission: AccessLevel) => {
      if (!currentDesignId || !user) return;
      const design = savedDesigns.find(d => d.housePlan.id === currentDesignId);
      if (!design) return;
      if (design.accessLevel !== 'owner') {
          setError("Only the project owner can share this design.");
          return;
      }
      try {
          await cloudService.shareDesign(user.email, currentDesignId, email, permission);
      } catch (e) {
          throw e;
      }
  }, [currentDesignId, user, savedDesigns]);

  if (isKeyReady === null || isAuthLoading) {
      return <LoadingOverlay message="Initializing..." />;
  }

  if (!user) {
      return (
        <>
            {isLoading && <LoadingOverlay message={loadingMessage} />}
            <LandingPage 
                onSignIn={handleSignIn} 
                onSignInGuest={handleSignInGuest}
                isKeyReady={isKeyReady !== false} 
                onSelectKey={handleSelectKey}
                error={error}
            />
        </>
      );
  }

  return (
    <div className="min-h-screen font-sans text-gray-900 dark:text-gray-100 transition-colors duration-300 flex flex-col">
      {isKeyReady === false && <ApiKeyPrompt onSelectKey={handleSelectKey} />}
      <Header 
        user={user}
        onSignIn={handleSignIn}
        onSignOut={handleSignOut}
        onNewDesign={resetApp}
        onSaveDesign={handleManualSaveToCloud}
        isSaving={isSavingCloud}
        hasActiveDesign={!!currentDesign}
        searchQuery={searchQuery} 
        onSearchChange={setSearchQuery} 
      />
      <main className="container mx-auto px-4 py-8 flex-grow">
        {isLoading && <LoadingOverlay message={loadingMessage} />}
        {view === AppView.Home && <HomePage 
            onGenerate={handleGenerationRequest} 
            error={error} 
            designs={filteredDesigns}
            onSelectDesign={handleSelectDesign}
            onDeleteDesign={handleDeleteDesign}
            onErrorClear={handleClearError}
            isKeyReady={isKeyReady}
            onSelectKey={handleSelectKey}
            user={user}
        />}
        {view === AppView.Results && currentDesign && (
          <ResultsPage
            key={currentDesign.housePlan.id}
            design={currentDesign}
            onNewRendering={handleNewRendering}
            onRefineRendering={handleRefineRendering}
            onUpdateRendering={updateRendering}
            onDeleteRenderings={deleteRenderings}
            onGenerateVideoTour={handleGenerateVideoTour}
            onRecreateRendering={handleRecreateRendering}
            onAddRoom={handleAddRoom}
            videoUrl={videoUrl}
            onCloseVideo={handleCloseVideo}
            error={error}
            onErrorClear={handleClearError}
            isLoading={isLoading}
            isKeyReady={isKeyReady}
            onSelectKey={handleSelectKey}
            onOpenShareModal={() => setIsShareModalOpen(true)}
            onReorderRenderings={handleReorderRenderings}
          />
        )}
      </main>

      <Footer />

      <ShareModal 
        isOpen={isShareModalOpen}
        onClose={() => setIsShareModalOpen(false)}
        onShare={handleShareDesign}
        designTitle={currentDesign?.housePlan.title || 'Project'}
      />
    </div>
  );
}

export default App;

import React, { useState, useEffect } from 'react';

const Footer: React.FC = () => {
  const [lastUpdated, setLastUpdated] = useState<string>('');
  const currentYear = new Date().getFullYear();

  useEffect(() => {
    // Generate timestamp in YYYYMMDDHHMISS format
    const now = new Date();
    const year = now.getFullYear();
    const month = String(now.getMonth() + 1).padStart(2, '0');
    const day = String(now.getDate()).padStart(2, '0');
    const hours = String(now.getHours()).padStart(2, '0');
    const minutes = String(now.getMinutes()).padStart(2, '0');
    const seconds = String(now.getSeconds()).padStart(2, '0');

    setLastUpdated(`${year}${month}${day}${hours}${minutes}${seconds}`);
  }, []);

  return (
    <footer className="w-full bg-white dark:bg-gray-900 border-t border-gray-200 dark:border-gray-800 py-6 mt-auto z-10 relative">
        <div className="container mx-auto px-4 text-center">
            <p className="text-sm font-bold text-gray-900 dark:text-white uppercase tracking-wider mb-2">
                A C.&.S.H. Group Properties A.I. APP
            </p>
            <div className="flex flex-col sm:flex-row justify-center items-center gap-y-1 gap-x-4 text-xs text-gray-500 dark:text-gray-400">
                <span>&copy; {currentYear} C.&.S.H. Group Properties</span>
                <span className="hidden sm:inline text-gray-300 dark:text-gray-700">|</span>
                <span className="font-mono">Last Updated: {lastUpdated}</span>
            </div>
        </div>
    </footer>
  );
};

export default Footer;

import React, { useState, useCallback, useEffect, useMemo, useRef } from 'react';
import { AppView, HousePlan, Rendering, SavedDesign, Room, User, AccessLevel } from './types';
import HomePage from './components/HomePage';
import ResultsPage from './components/ResultsPage';
import Header from './components/Header';
import LandingPage from './components/LandingPage';
import { generateHousePlanFromDescription, generateImage, generateVideo, generateImageFromImage } from './services/geminiService';
import { authService } from './services/authService';
import { dbService } from './services/dbService';
import { cloudService } from './services/cloudService';
import LoadingOverlay from './components/LoadingOverlay';
import ApiKeyPrompt from './components/ApiKeyPrompt';
import ShareModal from './components/ShareModal';
import Footer from './components/Footer';

interface UploadedFiles {
    frontPlan: File | null;
    backPlan: File | null;
    facadeImage: File | null;
}

function App() {
  const [view, setView] = useState<AppView>(AppView.Home);
  const [isLoading, setIsLoading] = useState(false);
  const [isAuthLoading, setIsAuthLoading] = useState(true);
  const [isSavingCloud, setIsSavingCloud] = useState(false);
  const [loadingMessage, setLoadingMessage] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [videoUrl, setVideoUrl] = useState<string | null>(null);

  const [savedDesigns, setSavedDesigns] = useState<SavedDesign[]>([]);
  const [currentDesignId, setCurrentDesignId] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [isKeyReady, setIsKeyReady] = useState<boolean | null>(null);
  const [isShareModalOpen, setIsShareModalOpen] = useState(false);

  const [user, setUser] = useState<User | null>(null);
  const userRef = useRef<User | null>(null);

  const getUserId = useCallback(() => {
    return user ? user.email : 'anonymous';
  }, [user]);

  const totalRenderingsCount = useMemo(() => {
    return savedDesigns.filter(d => d.accessLevel === 'owner').reduce((acc, design) => acc + design.renderings.length, 0);
  }, [savedDesigns]);

  useEffect(() => {
    const unsubscribe = authService.onAuthStateChanged((newUser) => {
      const prevEmail = userRef.current?.email;
      const newEmail = newUser?.email;

      if (prevEmail !== newEmail) {
          setUser(newUser);
      }
      setIsAuthLoading(false);
    });
    return () => unsubscribe();
  }, []);

  useEffect(() => {
      const handleDataLoadAndMigration = async () => {
        const currentUser = user;
        const previousUser = userRef.current;
        const currentUserId = currentUser ? currentUser.email : 'anonymous';

        userRef.current = currentUser;

        if (!currentUser) {
            setSavedDesigns([]);
            return;
        }

        if (currentUser && !previousUser) {
             try {
                const anonymousDesigns = await dbService.getUserDesigns('anonymous');
                if (anonymousDesigns.length > 0) {
                    setTimeout(async () => {
                         if (window.confirm(`Welcome ${currentUser.name}! You have designs saved as a guest. Would you like to move them to your account?`)) {
                            await dbService.reassignDesigns('anonymous', currentUser.email);
                            try {
                                const designs = await dbService.getUserDesigns(currentUser.email);
                                for (const design of designs) {
                                    await cloudService.saveDesign(currentUser.email, design);
                                }
                            } catch (err) {
                                console.warn("Background cloud sync failed during migration", err);
                            }
                            const designs = await dbService.getUserDesigns(currentUser.email);
                            setSavedDesigns(designs);
                        }
                    }, 500);
                }
             } catch (e) {
                 console.error("Error checking for anonymous designs:", e);
             }
        }

        try {
            let allDesigns = await dbService.getUserDesigns(currentUserId);
            allDesigns = allDesigns.map(d => ({ ...d, ownerId: currentUserId, accessLevel: 'owner' }));

            if (currentUser && currentUser.email !== 'anonymous') {
                try {
                    const cloudOwned = await cloudService.getUserDesigns(currentUserId);
                    const cloudShared = await cloudService.getSharedDesigns(currentUser.email);

                    for (const d of cloudOwned) {
                        await dbService.saveDesign(d, currentUserId);
                    }

                    const refreshedLocal = await dbService.getUserDesigns(currentUserId);
                    const finalOwned = refreshedLocal.map(d => ({ ...d, ownerId: currentUserId, accessLevel: 'owner' as AccessLevel }));
                    allDesigns = [...finalOwned, ...cloudShared];
                } catch (cloudErr) {
                    console.error("Cloud fetch failed, using local", cloudErr);
                }
            }
            setSavedDesigns(allDesigns);
        } catch (e) {
            console.error("Failed to load designs:", e);
            setError("Could not load saved designs.");
        }
      };

      if (!isAuthLoading) {
          handleDataLoadAndMigration();
      }
  }, [user, isAuthLoading]);

  const checkApiKey = useCallback(async () => {
    if (window.aistudio && typeof window.aistudio.hasSelectedApiKey === 'function') {
      try {
        const hasKey = await window.aistudio.hasSelectedApiKey();
        setIsKeyReady(hasKey);
      } catch (e) {
        console.error("Error checking for API key:", e);
        setIsKeyReady(false);
      }
    } else {
      setIsKeyReady(true);
    }
  }, []);

  useEffect(() => {
    checkApiKey();
  }, [checkApiKey]);

  const currentDesign = useMemo(() => {
    return savedDesigns.find(d => d.housePlan.id === currentDesignId) || null;
  }, [currentDesignId, savedDesigns]);

  const filteredDesigns = useMemo(() => {
    const sorted = [...savedDesigns].sort((a, b) => b.housePlan.createdAt - a.housePlan.createdAt);
    if (!searchQuery) return sorted;

    return sorted.filter(design => {
      const query = searchQuery.toLowerCase();
      const { title, style, rooms } = design.housePlan;
      return (
        title.toLowerCase().includes(query) ||
        style.toLowerCase().includes(query) ||
        rooms.some(room => room.name.toLowerCase().includes(query)) ||
        design.initialPrompt.toLowerCase().includes(query)
      );
    });
  }, [searchQuery, savedDesigns]);

  const saveDesignChange = useCallback(async (updatedDesign: SavedDesign) => {
      const currentUserId = getUserId();
      const designOwnerId = updatedDesign.ownerId || currentUserId;
      const isOwner = designOwnerId === currentUserId;

      try {
          setSavedDesigns(prev => {
              const idx = prev.findIndex(d => d.housePlan.id === updatedDesign.housePlan.id);
              if (idx >= 0) {
                  const newArr = [...prev];
                  newArr[idx] = updatedDesign;
                  return newArr;
              } else {
                  return [...prev, updatedDesign];
              }
          });

          if (isOwner) {
            await dbService.saveDesign(updatedDesign, currentUserId);
          }

          if (user && user.email !== 'anonymous') {
             await cloudService.saveDesign(designOwnerId, updatedDesign);
          }
      } catch (err) {
          console.error("Failed to save design:", err);
          setError("Failed to save changes.");
      }
  }, [getUserId, user]);

  const handleManualSaveToCloud = useCallback(async () => {
      if (!currentDesign) return;
      if (!user) {
          alert("You must be logged in to save to the cloud.");
          return;
      }

      setIsSavingCloud(true);
      try {
          const ownerId = currentDesign.ownerId || user.email;
          await cloudService.saveDesign(ownerId, currentDesign);
          if (ownerId === user.email) {
             await dbService.saveDesign(currentDesign, user.email);
          }
          alert("Design successfully saved!");
      } catch (err) {
          console.error(err);
          setError("Failed to save. Please try again.");
      } finally {
          setIsSavingCloud(false);
      }
  }, [currentDesign, user]);

  const handleError = useCallback((err: unknown, defaultView: AppView = AppView.Home) => {
    const errorMessage = err instanceof Error ? err.message : 'An unknown error occurred.';
    if (errorMessage.includes('billing-enabled API key') || errorMessage.includes('select a valid key') || errorMessage.includes('Requested entity was not found')) {
        setIsKeyReady(false);
    }
    setError(errorMessage);
    if (defaultView === AppView.Home) {
        setView(AppView.Home);
    }
  }, []);

  const resetApp = useCallback(() => {
    setView(AppView.Home);
    setCurrentDesignId(null);
    setError(null);
    setIsLoading(false);
    setSearchQuery('');
    setVideoUrl(prev => {
        if(prev) URL.revokeObjectURL(prev);
        return null;
    });
  }, []);

  const handleSignOut = useCallback(async () => {
    await authService.signOut();
    resetApp();
  }, [resetApp]);

  const checkGuestLimit = useCallback(() => {
     if (user?.name === 'Guest Architect' && totalRenderingsCount >= 2) {
         if (window.confirm("Guest Account Limit Reached\n\nYou are limited to 2 active renderings as a Guest.\n\nPlease Sign In with your Google Account to create unlimited designs, access cloud storage, and advanced features.")) {
             handleSignOut();
         }
         return false;
     }
     return true;
  }, [user, totalRenderingsCount, handleSignOut]);

  const handleGenerationRequest = useCallback(async (description: string, files: UploadedFiles) => {
    if (!checkGuestLimit()) return;

    setIsLoading(true);
    setError(null);
    setLoadingMessage('Processing your design inputs...');

    try {
      const imageInputs: { file: File, description: string }[] = [];
      if (files.frontPlan) imageInputs.push({ file: files.frontPlan, description: "front architectural plan" });
      if (files.backPlan) imageInputs.push({ file: files.backPlan, description: "back architectural plan" });
      if (files.facadeImage) imageInputs.push({ file: files.facadeImage, description: "example facade for style reference" });

      const processedImages = await Promise.all(imageInputs.map(async (input) => {
          const reader = new FileReader();
          const base64 = await new Promise<string>((resolve, reject) => {
              reader.onload = () => resolve((reader.result as string).split(',')[1]);
              reader.onerror = reject;
              reader.readAsDataURL(input.file);
          });
          return { base64, mimeType: input.file.type, description: input.description };
      }));

      setLoadingMessage('Designing your dream home structure...');
      const planData = await generateHousePlanFromDescription(description, processedImages);

      const newHousePlan: HousePlan = {
          ...planData,
          id: crypto.randomUUID(),
          createdAt: Date.now(),
      };

      let frontImageUrl: string;
      let frontExteriorPrompt: string;
      const facadeForRendering = processedImages.find(p => p.description.includes('facade'));

      if (facadeForRendering) {
        setLoadingMessage('Rendering 3D model from your image...');
        frontExteriorPrompt = `Using the provided example facade image as a strong style reference, create a photorealistic, high-quality 3D architectural rendering of a complete house exterior. The overall design concept is: "${description}". Enhance the lighting, textures, and surroundings to create a professional visualization.`;
        frontImageUrl = await generateImageFromImage(frontExteriorPrompt, facadeForRendering.base64, facadeForRendering.mimeType);
      } else {
        setLoadingMessage('Rendering front exterior...');
        frontExteriorPrompt = `Photorealistic 3D rendering of the front exterior of a ${newHousePlan.style} house. This image should focus on the street-facing view, including the main entrance, facade, and any front yard landscaping. The overall architectural concept is: "${description}". Crucially, DO NOT include backyard-specific features like swimming pools, large patios, or putting greens in this front view.`;
        frontImageUrl = await generateImage(frontExteriorPrompt);
      }

      const frontRendering: Rendering = {
        id: crypto.randomUUID(),
        category: 'Front Exterior',
        imageUrl: frontImageUrl,
        prompt: frontExteriorPrompt,
        liked: false,
        favorited: false
      };

      const newDesign: SavedDesign = {
        housePlan: newHousePlan,
        renderings: [frontRendering],
        initialPrompt: description,
        uploadedImages: {
            frontPlan: processedImages.find(p => p.description.includes('front architectural plan')),
            backPlan: processedImages.find(p => p.description.includes('back architectural plan')),
            facadeImage: processedImages.find(p => p.description.includes('facade'))
        },
        ownerId: getUserId(),
        accessLevel: 'owner'
      };

      await saveDesignChange(newDesign);
      setCurrentDesignId(newHousePlan.id);
      setView(AppView.Results);

    } catch (err) {
      handleError(err, AppView.Home);
    } finally {
      setIsLoading(false);
      setLoadingMessage('');
    }
  }, [saveDesignChange, handleError, getUserId, checkGuestLimit]);

  const handleNewRendering = useCallback(async (prompt: string, category: string) => {
    if (!currentDesignId) return;
    if (!checkGuestLimit()) return;

    setIsLoading(true);
    setLoadingMessage(`Rendering ${category}...`);
    setError(null);
    try {
      const design = savedDesigns.find(d => d.housePlan.id === currentDesignId);
      if (!design) return;

      let imageUrl: string;
      const backPlanImage = design?.uploadedImages?.backPlan;

      if (category === 'Back Exterior' && backPlanImage) {
        imageUrl = await generateImageFromImage(prompt, backPlanImage.base64, backPlanImage.mimeType);
      } else {
        imageUrl = await generateImage(prompt);
      }

      const newRendering: Rendering = {
        id: crypto.randomUUID(),
        category,
        imageUrl,
        prompt,
        liked: false,
        favorited: false
      };

      const updatedDesign = { ...design, renderings: [...design.renderings, newRendering] };
      await saveDesignChange(updatedDesign);

    } catch (err) {
      handleError(err);
    } finally {
      setIsLoading(false);
      setLoadingMessage('');
    }
  }, [currentDesignId, savedDesigns, saveDesignChange, handleError, checkGuestLimit]);

  const handleRefineRendering = useCallback(async (renderingId: string, instructions: string) => {
    if (!currentDesignId) return;
    const design = savedDesigns.find(d => d.housePlan.id === currentDesignId);
    if (!design) return;

    if (design.accessLevel === 'view') {
        alert("You have 'View Only' access to this project.");
        return;
    }

    const rendering = design.renderings.find(r => r.id === renderingId);
    if (!rendering) return;

    setIsLoading(true);
    setLoadingMessage(`Refining ${rendering.category}...`);
    setError(null);

    try {
        const base64Data = rendering.imageUrl.split(',')[1];
        const mimeType = rendering.imageUrl.split(';')[0].split(':')[1];

        const refinePrompt = `You are a professional architectural visualizer. Modify the provided image according to these specific instructions: "${instructions}". Keep the overall structure and style consistent with the original image, but precisely apply the requested changes (adding or removing elements as described). Ensure the output is a high-quality photorealistic architectural rendering.`;

        const refinedImageUrl = await generateImageFromImage(refinePrompt, base64Data, mimeType);

        const updatedRendering: Rendering = {
            ...rendering,
            imageUrl: refinedImageUrl,
            prompt: `${rendering.prompt} | Refined with: ${instructions}`
        };

        const newRenderings = design.renderings.map(r => r.id === renderingId ? updatedRendering : r);
        const updatedDesign = { ...design, renderings: newRenderings };
        await saveDesignChange(updatedDesign);

    } catch (err) {
        handleError(err);
    } finally {
        setIsLoading(false);
        setLoadingMessage('');
    }
  }, [currentDesignId, savedDesigns, saveDesignChange, handleError]);

  const handleRecreateRendering = useCallback(async (category: string) => {
    if (!currentDesignId) return;
    const design = savedDesigns.find(d => d.housePlan.id === currentDesignId);
    if (!design) return;

    if (design.accessLevel === 'view') {
        alert("You have 'View Only' access to this project.");
        return;
    }

    const existingRendering = design.renderings.find(r => r.category === category);
    if (!existingRendering || (category !== 'Front Exterior' && category !== 'Back Exterior')) return;

    setIsLoading(true);
    setLoadingMessage(`Re-creating ${category}...`);
    setError(null);

    try {
      const { prompt } = existingRendering;
      let imageUrl: string;

      if (category === 'Front Exterior') {
         const facadeImage = design.uploadedImages?.facadeImage;
         if (facadeImage && prompt.includes("example facade")) {
            imageUrl = await generateImageFromImage(prompt, facadeImage.base64, facadeImage.mimeType);
         } else {
            imageUrl = await generateImage(prompt);
         }
      } else {
         const backPlan = design.uploadedImages?.backPlan;
         if (backPlan) {
            imageUrl = await generateImageFromImage(prompt, backPlan.base64, backPlan.mimeType);
         } else {
            imageUrl = await generateImage(prompt);
         }
      }

      const updatedRendering: Rendering = {
          ...existingRendering,
          imageUrl,
      };

      const newRenderings = design.renderings.map(r => r.id === existingRendering.id ? updatedRendering : r);
      const updatedDesign = { ...design, renderings: newRenderings };
      await saveDesignChange(updatedDesign);

    } catch (err) {
      handleError(err);
    } finally {
      setIsLoading(false);
      setLoadingMessage('');
    }
  }, [currentDesignId, savedDesigns, saveDesignChange, handleError]);

  const handleGenerateVideoTour = useCallback(async (prompt: string) => {
      setIsLoading(true);
      setLoadingMessage('Creating cinematic tour... This may take minutes.');
      setError(null);
      try {
          const url = await generateVideo(prompt);
          setVideoUrl(url);
      } catch (err) {
        handleError(err);
      } finally {
          setIsLoading(false);
          setLoadingMessage('');
      }
  }, [handleError]);

  const handleCloseVideo = useCallback(() => {
    if (videoUrl) {
      URL.revokeObjectURL(videoUrl);
    }
    setVideoUrl(null);
  }, [videoUrl]);

  const updateRendering = useCallback(async (renderingId: string, updates: Partial<Rendering>) => {
    if (!currentDesignId) return;
    const design = savedDesigns.find(d => d.housePlan.id === currentDesignId);
    if (!design) return;

    const newRenderings = design.renderings.map(r => r.id === renderingId ? { ...r, ...updates } : r);
    const updatedDesign = { ...design, renderings: newRenderings };
    await saveDesignChange(updatedDesign);
  }, [currentDesignId, savedDesigns, saveDesignChange]);

  const deleteRenderings = useCallback(async (renderingIds: string[]) => {
    if (!currentDesignId) return;
    const design = savedDesigns.find(d => d.housePlan.id === currentDesignId);
    if (!design) return;

    if (design.accessLevel === 'view') return;

    const newRenderings = design.renderings.filter(r => !renderingIds.includes(r.id));
    const updatedDesign = { ...design, renderings: newRenderings };
    await saveDesignChange(updatedDesign);
  }, [currentDesignId, savedDesigns, saveDesignChange]);

  const handleReorderRenderings = useCallback(async (reorderedRenderings: Rendering[]) => {
    if (!currentDesignId) return;
    const design = savedDesigns.find(d => d.housePlan.id === currentDesignId);
    if (!design) return;

    if (design.accessLevel === 'view') return;

    const updatedDesign = { ...design, renderings: reorderedRenderings };
    await saveDesignChange(updatedDesign);
  }, [currentDesignId, savedDesigns, saveDesignChange]);

  const handleSelectDesign = useCallback((designId: string) => {
    setCurrentDesignId(designId);
    setView(AppView.Results);
    setError(null);
  }, []);

  const handleDeleteDesign = useCallback(async (designId: string) => {
    const design = savedDesigns.find(d => d.housePlan.id === designId);
    if (!design) return;

    const isOwner = design.accessLevel === 'owner';
    const message = isOwner 
        ? "Are you sure you want to delete this design and all its renderings? This action cannot be undone."
        : "Remove this shared design from your list?";

    if (window.confirm(message)) {
      try {
        const userId = getUserId();

        if (isOwner) {
            await dbService.deleteDesign(designId);
            if (user && user.email !== 'anonymous') {
                await cloudService.deleteDesign(userId, designId);
            }
        } else {
            if (user) {
                await cloudService.removeShare(user.email, designId);
            }
        }

        setSavedDesigns(prev => prev.filter(d => d.housePlan.id !== designId));
        if (currentDesignId === designId) {
            resetApp();
        }
      } catch (err) {
        console.error("Failed to delete design", err);
        setError("Failed to delete design.");
      }
    }
  }, [currentDesignId, resetApp, getUserId, user, savedDesigns]);

  const handleAddRoom = useCallback(async (newRoom: Room) => {
    if (!currentDesignId) return;
    const design = savedDesigns.find(d => d.housePlan.id === currentDesignId);
    if (!design) return;

    if (design.accessLevel === 'view') return;

    const updatedHousePlan = {
        ...design.housePlan,
        rooms: [...design.housePlan.rooms, newRoom]
    };
    const updatedDesign = { ...design, housePlan: updatedHousePlan };
    await saveDesignChange(updatedDesign);
  }, [currentDesignId, savedDesigns, saveDesignChange]);

  const handleSelectKey = useCallback(async () => {
      if (window.aistudio && typeof window.aistudio.openSelectKey === 'function') {
        try {
          await window.aistudio.openSelectKey();
          setIsKeyReady(true);
          checkApiKey();
        } catch (e) {
          setError("Could not open API key selection. Please try again.");
        }
      } else {
          setIsKeyReady(true);
      }
  }, [checkApiKey]);

  const handleClearError = useCallback(() => setError(null), []);

  const handleSignIn = useCallback(async () => {
      setIsLoading(true);
      setLoadingMessage("Signing in with Google...");
      try {
        await authService.signIn();
      } catch (e) {
        setError("Sign in failed. Please try again.");
      } finally {
        setIsLoading(false);
        setLoadingMessage('');
      }
  }, []);

  const handleSignInGuest = useCallback(async () => {
      setIsLoading(true);
      setLoadingMessage("Setting up Guest Account...");
      try {
        await authService.signInGuest();
      } catch (e) {
        console.error("Guest Sign In Error:", e);
        setError("Guest sign in failed. Please try again.");
      } finally {
        setIsLoading(false);
        setLoadingMessage('');
      }
  }, []);

  const handleShareDesign = useCallback(async (email: string, permission: AccessLevel) => {
      if (!currentDesignId || !user) return;
      const design = savedDesigns.find(d => d.housePlan.id === currentDesignId);
      if (!design) return;
      if (design.accessLevel !== 'owner') {
          setError("Only the project owner can share this design.");
          return;
      }
      try {
          await cloudService.shareDesign(user.email, currentDesignId, email, permission);
      } catch (e) {
          throw e;
      }
  }, [currentDesignId, user, savedDesigns]);

  if (isKeyReady === null || isAuthLoading) {
      return <LoadingOverlay message="Initializing..." />;
  }

  if (!user) {
      return (
        <>
            {isLoading && <LoadingOverlay message={loadingMessage} />}
            <LandingPage 
                onSignIn={handleSignIn} 
                onSignInGuest={handleSignInGuest}
                isKeyReady={isKeyReady !== false} 
                onSelectKey={handleSelectKey}
                error={error}
            />
        </>
      );
  }

  return (
    <div className="min-h-screen font-sans text-gray-900 dark:text-gray-100 transition-colors duration-300 flex flex-col">
      {isKeyReady === false && <ApiKeyPrompt onSelectKey={handleSelectKey} />}
      <Header 
        user={user}
        onSignIn={handleSignIn}
        onSignOut={handleSignOut}
        onNewDesign={resetApp}
        onSaveDesign={handleManualSaveToCloud}
        isSaving={isSavingCloud}
        hasActiveDesign={!!currentDesign}
        searchQuery={searchQuery} 
        onSearchChange={setSearchQuery} 
      />
      <main className="container mx-auto px-4 py-8 flex-grow">
        {isLoading && <LoadingOverlay message={loadingMessage} />}
        {view === AppView.Home && <HomePage 
            onGenerate={handleGenerationRequest} 
            error={error} 
            designs={filteredDesigns}
            onSelectDesign={handleSelectDesign}
            onDeleteDesign={handleDeleteDesign}
            onErrorClear={handleClearError}
            isKeyReady={isKeyReady}
            onSelectKey={handleSelectKey}
            user={user}
        />}
        {view === AppView.Results && currentDesign && (
          <ResultsPage
            key={currentDesign.housePlan.id}
            design={currentDesign}
            onNewRendering={handleNewRendering}
            onRefineRendering={handleRefineRendering}
            onUpdateRendering={updateRendering}
            onDeleteRenderings={deleteRenderings}
            onGenerateVideoTour={handleGenerateVideoTour}
            onRecreateRendering={handleRecreateRendering}
            onAddRoom={handleAddRoom}
            videoUrl={videoUrl}
            onCloseVideo={handleCloseVideo}
            error={error}
            onErrorClear={handleClearError}
            isLoading={isLoading}
            isKeyReady={isKeyReady}
            onSelectKey={handleSelectKey}
            onOpenShareModal={() => setIsShareModalOpen(true)}
            onReorderRenderings={handleReorderRenderings}
          />
        )}
      </main>

      <Footer />

      <ShareModal 
        isOpen={isShareModalOpen}
        onClose={() => setIsShareModalOpen(false)}
        onShare={handleShareDesign}
        designTitle={currentDesign?.housePlan.title || 'Project'}
      />
    </div>
  );
}

export default App;

